def automation_center_preview(action_id: str, payload: dict, user: dict[str, str]) -> dict[str, object]:
    action = automation_action_config(action_id, user)
    if action_id == "management_rules":
        preview = preview_management_rules()
    elif action_id == "bulk_db_change":
        preview = preview_bulk_db_change(payload)
    elif action_id == "mail_failure_ops":
        preview = preview_mail_failure_ops()
    elif action_id == "cs_bulk_mail":
        preview = preview_cs_bulk_mail()
    elif action_id == "notice_auto":
        preview = preview_notice_auto(user)
    elif action_id == "backup_ops":
        preview = preview_backup_ops()
    else:
        raise ValueError("지원하지 않는 자동화 기능입니다.")
    return {"action": action, "preview": preview}


def automation_center_execute(action_id: str, payload: dict, user: dict[str, str]) -> dict[str, object]:
    action = automation_action_config(action_id, user)
    backup_name = ""
    if action_id in {"management_rules", "bulk_db_change"}:
        backup = create_workhub_backup(reason=f"automation-{action_id}", upload_external=False)
        backup_name = str(backup["name"])
    preview = automation_center_preview(action_id, payload, user)["preview"]
    if action_id == "management_rules":
        result = execute_management_rules()
    elif action_id == "bulk_db_change":
        result = execute_bulk_db_change(payload)
    elif action_id == "mail_failure_ops":
        result = execute_mail_failure_ops(user)
    elif action_id == "cs_bulk_mail":
        result = execute_cs_bulk_mail(user)
    elif action_id == "notice_auto":
        result = execute_notice_auto(user)
    elif action_id == "backup_ops":
        result = execute_backup_ops()
        first = result.get("rows", [{}])[0] if result.get("rows") else {}
        backup_name = str(first.get("내용") or "")
    else:
        raise ValueError("지원하지 않는 자동화 기능입니다.")
    message = str(result.get("summary") or "자동화 실행이 완료되었습니다.")
    record_automation_operation(action, "executed", user, payload=payload, preview=preview, result=result, backup_name=backup_name, message=message)
    return {"message": message, "result": result, "backup_name": backup_name}


def sales_report_detail_payload(kind: str, key: str, period: str = "") -> dict[str, object]:
    init_db()
    connection = connect_db()
    try:
        selected_period = period or latest_sales_report_period(connection)
        detail_kind = str(kind or "").strip().lower()
        detail_key = str(key or "").strip()
        if not selected_period:
            raise ValueError("조회할 매출 월 데이터가 없습니다.")
        if not detail_key:
            raise ValueError("상세 조회 기준이 없습니다.")

        if detail_kind == "daily":
            summary = connection.execute(
                "SELECT * FROM sales_report_daily_rows WHERE period = ? AND report_date = ?",
                (selected_period, detail_key),
            ).fetchone()
            current_seller_total = connection.execute(
                """
                SELECT COUNT(*) AS row_count,
                       COALESCE(SUM(profit_sales_amount), 0) AS profit_sales_amount
                  FROM sales_report_seller_rows
                 WHERE period = ? AND report_date = ?
                """,
                (selected_period, detail_key),
            ).fetchone()
            daily_profit_sales = int(summary["profit_sales_amount"] or 0) if summary else 0
            current_profit_sales = int(current_seller_total["profit_sales_amount"] or 0) if current_seller_total else 0
            current_seller_count = int(current_seller_total["row_count"] or 0) if current_seller_total else 0
            use_seller_amounts = current_seller_count > 0 or (
                daily_profit_sales > 0 and abs(current_profit_sales - daily_profit_sales) <= max(1000, int(abs(daily_profit_sales) * 0.05))
            )
            seller_rows = connection.execute(
                """
                WITH current_rows AS (
                    SELECT TRIM(seller_name) AS seller_name,
                           COALESCE(SUM(quantity), 0) AS quantity,
                           COALESCE(SUM(profit_sales_amount), 0) AS profit_sales_amount,
                           COALESCE(SUM(sales_total), 0) AS sales_total,
                           COALESCE(SUM(profit_margin - profit_shipping), 0) AS profit_margin
                      FROM sales_report_seller_rows
                     WHERE period = ? AND report_date = ?
                     GROUP BY TRIM(seller_name)
                ),
                ledger_rows AS (
                    SELECT TRIM(COALESCE(NULLIF(sales_vendor, ''), '판매처 미입력')) AS seller_name,
                           COUNT(*) AS order_count,
                           COALESCE(SUM(CAST(REPLACE(quantity, ',', '') AS INTEGER)), 0) AS ledger_quantity
                      FROM management_records
                     WHERE substr(COALESCE(NULLIF(ship_date, ''), NULLIF(order_date, '')), 1, 10) = ?
                     GROUP BY TRIM(COALESCE(NULLIF(sales_vendor, ''), '판매처 미입력'))
                ),
                keys AS (
                    SELECT seller_name FROM current_rows
                    UNION
                    SELECT seller_name FROM ledger_rows
                )
                SELECT keys.seller_name,
                       COALESCE(ledger_rows.order_count, 0) AS order_count,
                       CASE
                           WHEN ledger_rows.seller_name IS NOT NULL THEN COALESCE(ledger_rows.ledger_quantity, 0)
                           ELSE COALESCE(current_rows.quantity, 0)
                       END AS quantity,
                       COALESCE(current_rows.profit_sales_amount, 0) AS profit_sales_amount,
                       COALESCE(current_rows.sales_total, 0) AS sales_total,
                       COALESCE(current_rows.profit_margin, 0) AS profit_margin
                  FROM keys
                  LEFT JOIN current_rows ON current_rows.seller_name = keys.seller_name
                  LEFT JOIN ledger_rows ON ledger_rows.seller_name = keys.seller_name
                 WHERE COALESCE(ledger_rows.order_count, 0) != 0
                    OR COALESCE(current_rows.quantity, 0) != 0
                    OR COALESCE(current_rows.profit_sales_amount, 0) != 0
                    OR COALESCE(current_rows.sales_total, 0) != 0
                 ORDER BY profit_sales_amount DESC, sales_total DESC, quantity DESC, order_count DESC, keys.seller_name COLLATE NOCASE
                """,
                (selected_period, detail_key, detail_key),
            ).fetchall()
            product_rows = connection.execute(
                """
                SELECT TRIM(COALESCE(NULLIF(product_name, ''), '상품명 미입력')) AS product_name,
                       TRIM(COALESCE(NULLIF(sales_vendor, ''), '판매처 미입력')) AS seller_name,
                       COUNT(*) AS order_count,
                       COALESCE(SUM(CAST(REPLACE(quantity, ',', '') AS INTEGER)), 0) AS quantity
                  FROM management_records
                 WHERE substr(COALESCE(NULLIF(ship_date, ''), NULLIF(order_date, '')), 1, 10) = ?
                 GROUP BY TRIM(COALESCE(NULLIF(product_name, ''), '상품명 미입력')),
                          TRIM(COALESCE(NULLIF(sales_vendor, ''), '판매처 미입력'))
                 ORDER BY seller_name COLLATE NOCASE, quantity DESC, order_count DESC, product_name COLLATE NOCASE
                """,
                (detail_key,),
            ).fetchall()
            seller_quantity_total = sum(int(row["quantity"] or 0) for row in seller_rows)
            seller_profit_sales_total = sum(int(row["profit_sales_amount"] or 0) for row in seller_rows)
            seller_sales_total = sum(int(row["sales_total"] or 0) for row in seller_rows)
            seller_profit_margin_total = sum(int(row["profit_margin"] or 0) for row in seller_rows)
            summary_quantity = int(summary["quantity"] or 0) if summary else 0
            summary_profit_sales = int(summary["profit_sales_amount"] or 0) if summary else 0
            summary_sales_total = int(summary["sales_total"] or 0) if summary else 0
            summary_profit_margin = int((summary["profit_margin"] or 0) - (summary["profit_shipping"] or 0)) if summary else 0
            return {
                "kind": "daily",
                "title": f"{detail_key} 판매사별 당일 현황",
                "period": selected_period,
                "note": "판매금액은 해당 날짜 매출처별 매출표 기준으로 표시하고, 주문건수는 통합관리대장의 해당 날짜 기준으로 보조 표시합니다." if use_seller_amounts else "해당 날짜의 매출처별 금액 데이터가 없어 통합관리대장 기준 주문건수와 수량만 표시합니다.",
                "metrics": [
                    _sales_detail_metric("수량", summary_quantity or seller_quantity_total),
                    _sales_detail_metric("손익매출", summary_profit_sales or seller_profit_sales_total),
                    _sales_detail_metric("판매합계", summary_sales_total or seller_sales_total),
                    _sales_detail_metric("손익마진(택배비 제외)", summary_profit_margin or seller_profit_margin_total),
                ],
                "sections": [
                    {
                        "title": "해당 날짜 판매사별 발생 건",
                        "headers": ["판매사", "주문건수", "수량", "손익매출", "판매합계", "손익마진(택배비 제외)"],
                        "rows": [
                            [
                                str(row["seller_name"] or ""),
                                int(row["order_count"] or 0),
                                int(row["quantity"] or 0),
                                int(row["profit_sales_amount"] or 0),
                                int(row["sales_total"] or 0),
                                int(row["profit_margin"] or 0),
                            ]
                            for row in seller_rows
                        ],
                        "empty": "해당 날짜에 발생한 판매사별 주문/출고 데이터가 없습니다.",
                    },
                    {
                        "title": "출고 제품 리스트",
                        "headers": ["제품명", "판매처", "주문건수", "출고수량"],
                        "rows": [
                            [
                                str(row["product_name"] or ""),
                                str(row["seller_name"] or ""),
                                int(row["order_count"] or 0),
                                int(row["quantity"] or 0),
                            ]
                            for row in product_rows
                        ],
                        "empty": "해당 날짜의 출고 제품 데이터를 찾지 못했습니다.",
                    }
                ],
            }

        if detail_kind == "product":
            shipment_rows = connection.execute(
                """
                WITH source AS (
                    SELECT COALESCE(NULLIF(ship_date, ''), NULLIF(order_date, '')) AS sales_date,
                           quantity
                      FROM management_records
                     WHERE COALESCE(NULLIF(ship_date, ''), NULLIF(order_date, '')) LIKE ?
                       AND product_name != ''
                       AND (product_name = ? OR instr(product_name, ?) > 0 OR instr(?, product_name) > 0)
                )
                SELECT substr(sales_date, 1, 10) AS sales_date,
                       COUNT(*) AS order_count,
                       COALESCE(SUM(CAST(REPLACE(quantity, ',', '') AS INTEGER)), 0) AS quantity
                  FROM source
                 GROUP BY substr(sales_date, 1, 10)
                 ORDER BY sales_date DESC
                """,
                (f"{selected_period}%", detail_key, detail_key, detail_key),
            ).fetchall()
            seller_rows = connection.execute(
                """
                WITH source AS (
                    SELECT COALESCE(NULLIF(sales_vendor, ''), '판매처 미입력') AS sales_vendor,
                           quantity
                      FROM management_records
                     WHERE COALESCE(NULLIF(ship_date, ''), NULLIF(order_date, '')) LIKE ?
                       AND product_name != ''
                       AND (product_name = ? OR instr(product_name, ?) > 0 OR instr(?, product_name) > 0)
                )
                SELECT sales_vendor,
                       COUNT(*) AS order_count,
                       COALESCE(SUM(CAST(REPLACE(quantity, ',', '') AS INTEGER)), 0) AS quantity
                  FROM source
                 GROUP BY sales_vendor
                 ORDER BY quantity DESC, order_count DESC, sales_vendor COLLATE NOCASE
                """,
                (f"{selected_period}%", detail_key, detail_key, detail_key),
            ).fetchall()
            shipped_quantity = sum(int(row["quantity"] or 0) for row in shipment_rows)
            seller_count = len(seller_rows)
            return {
                "kind": "product",
                "title": f"{detail_key} 상세",
                "period": selected_period,
                "note": "통합관리대장의 해당 월 출고일과 판매처별 수량만 표시합니다.",
                "metrics": [
                    _sales_detail_metric("출고 수량", shipped_quantity),
                    _sales_detail_metric("출고 일수", len(shipment_rows)),
                    _sales_detail_metric("판매처 수", seller_count),
                ],
                "sections": [
                    {
                        "title": "일자별 출고 현황",
                        "headers": ["출고일", "주문건수", "출고수량"],
                        "rows": [
                            [str(row["sales_date"] or ""), int(row["order_count"] or 0), int(row["quantity"] or 0)]
                            for row in shipment_rows
                        ],
                        "empty": "통합관리대장에서 해당 상품의 출고 데이터를 찾지 못했습니다.",
                    },
                    {
                        "title": "판매처별 판매수량",
                        "headers": ["판매처", "주문건수", "판매수량"],
                        "rows": [
                            [str(row["sales_vendor"] or ""), int(row["order_count"] or 0), int(row["quantity"] or 0)]
                            for row in seller_rows
                        ],
                        "empty": "통합관리대장에서 해당 상품의 판매처별 수량을 찾지 못했습니다.",
                    },
                ],
            }

        if detail_kind in {"seller", "supplier"}:
            is_seller = detail_kind == "seller"
            table_name = "sales_report_seller_rows" if is_seller else "sales_report_supplier_rows"
            name_column = "seller_name" if is_seller else "supplier_name"
            amount_column = "profit_sales_amount" if is_seller else "supply_total"
            sales_summary = connection.execute(
                f"""
                SELECT COALESCE(SUM(quantity), 0) AS quantity,
                       COALESCE(SUM({amount_column}), 0) AS amount,
                       COALESCE(SUM(profit_margin - profit_shipping), 0) AS profit_margin
                   FROM {table_name}
                  WHERE period = ? AND {name_column} = ?
                 """,
                (selected_period, detail_key),
            ).fetchone()
            vendor_column = "sales_vendor" if is_seller else "purchase_vendor"
            ledger_rows = connection.execute(
                f"""
                WITH source AS (
                    SELECT COALESCE(NULLIF(ship_date, ''), NULLIF(order_date, '')) AS activity_date,
                           quantity
                      FROM management_records
                     WHERE COALESCE(NULLIF(ship_date, ''), NULLIF(order_date, '')) LIKE ?
                       AND {vendor_column} = ?
                )
                SELECT substr(activity_date, 1, 10) AS activity_date,
                       COUNT(*) AS order_count,
                       COALESCE(SUM(CAST(REPLACE(quantity, ',', '') AS INTEGER)), 0) AS quantity
                  FROM source
                 GROUP BY substr(activity_date, 1, 10)
                 ORDER BY activity_date ASC
                """,
                (f"{selected_period}%", detail_key),
            ).fetchall()
            product_rows = connection.execute(
                f"""
                SELECT substr(COALESCE(NULLIF(ship_date, ''), NULLIF(order_date, '')), 1, 10) AS activity_date,
                       TRIM(COALESCE(NULLIF(product_name, ''), '상품명 미입력')) AS product_name,
                       COUNT(*) AS order_count,
                       COALESCE(SUM(CAST(REPLACE(quantity, ',', '') AS INTEGER)), 0) AS quantity
                  FROM management_records
                 WHERE COALESCE(NULLIF(ship_date, ''), NULLIF(order_date, '')) LIKE ?
                   AND {vendor_column} = ?
                 GROUP BY substr(COALESCE(NULLIF(ship_date, ''), NULLIF(order_date, '')), 1, 10),
                          TRIM(COALESCE(NULLIF(product_name, ''), '상품명 미입력'))
                 ORDER BY activity_date DESC, quantity DESC, order_count DESC, product_name COLLATE NOCASE
                """,
                (f"{selected_period}%", detail_key),
            ).fetchall()
            amount_date_stats = connection.execute(
                f"""
                SELECT COUNT(DISTINCT rows.report_date) AS date_count,
                       COALESCE(SUM(CASE WHEN uploads.report_type = 'seller_daily_zip' THEN 1 ELSE 0 END), 0) AS daily_zip_rows
                  FROM {table_name} AS rows
                  LEFT JOIN sales_report_uploads AS uploads ON uploads.id = rows.file_id
                 WHERE rows.period = ? AND rows.{name_column} = ? AND rows.report_date != ''
                """,
                (selected_period, detail_key),
            ).fetchone()
            amount_detail_active = bool(amount_date_stats) and int(amount_date_stats["date_count"] or 0) > 0
            amount_rows = []
            if amount_detail_active:
                amount_rows = connection.execute(
                    f"""
                    SELECT report_date,
                           COALESCE(SUM(quantity), 0) AS quantity_delta,
                           COALESCE(SUM({amount_column}), 0) AS amount_delta,
                           COALESCE(SUM(profit_margin - profit_shipping), 0) AS margin_delta
                      FROM {table_name}
                     WHERE period = ? AND {name_column} = ? AND report_date != ''
                     GROUP BY report_date
                     ORDER BY report_date
                    """,
                    (selected_period, detail_key),
                ).fetchall()
            amount_by_date = {
                str(row["report_date"] or ""): {
                    "quantity_delta": row["quantity_delta"],
                    "amount_delta": row["amount_delta"],
                    "margin_delta": row["margin_delta"],
                }
                for row in amount_rows
            }
            ledger_by_date = {
                str(row["activity_date"] or ""): {
                    "order_count": int(row["order_count"] or 0),
                    "quantity": int(row["quantity"] or 0),
                }
                for row in ledger_rows
            }
            detail_dates = sorted(set(ledger_by_date) | set(amount_by_date))
            rows = [
                {
                    "activity_date": activity_date,
                    "order_count": ledger_by_date.get(activity_date, {}).get("order_count", 0),
                    "quantity": ledger_by_date.get(activity_date, {}).get("quantity", 0),
                    "amount_delta": amount_by_date.get(activity_date, {}).get("amount_delta"),
                    "margin_delta": amount_by_date.get(activity_date, {}).get("margin_delta"),
                }
                for activity_date in detail_dates
            ]
            amount_detail_rows = [
                row
                for row in rows
                if row["amount_delta"] is not None or row["margin_delta"] is not None
            ]
            total_quantity = sum(int(row["quantity"] or 0) for row in rows)
            total_orders = sum(int(row["order_count"] or 0) for row in rows)
            total_amount = int(sales_summary["amount"] or 0) if sales_summary else 0
            total_margin = int(sales_summary["profit_margin"] or 0) if sales_summary else 0
            return {
                "kind": detail_kind,
                "title": f"{detail_key} {'매출처' if is_seller else '매입처'} 월 전체 현황",
                "period": selected_period,
                "note": "월 전체 주문건수와 수량은 통합관리대장 기준입니다. 일자별 금액은 거래처별 업로드 파일의 일자 기준 금액을 표시합니다.",
                "metrics": [
                    _sales_detail_metric("주문건수", total_orders),
                    _sales_detail_metric("관리대장 수량", total_quantity),
                    _sales_detail_metric("매출금액" if is_seller else "매입금액", total_amount),
                    _sales_detail_metric("손익마진(택배비 제외)", total_margin),
                ],
                "sections": [
                    {
                        "title": "월 전체 주문/수량",
                        "headers": ["일자", "주문건수", "수량"],
                        "rows": [
                            [
                                str(row["activity_date"] or ""),
                                int(row["order_count"] or 0),
                                int(row["quantity"] or 0),
                            ]
                            for row in rows
                        ],
                        "empty": "해당 거래처의 월 전체 관리대장 데이터가 없습니다.",
                    },
                    {
                        "title": "출고 제품 리스트",
                        "headers": ["출고일", "제품명", "주문건수", "출고수량"],
                        "rows": [
                            [
                                str(row["activity_date"] or ""),
                                str(row["product_name"] or ""),
                                int(row["order_count"] or 0),
                                int(row["quantity"] or 0),
                            ]
                            for row in product_rows
                        ],
                        "empty": "해당 거래처의 출고 제품 데이터를 찾지 못했습니다.",
                    },
                    {
                        "title": "일자별 금액",
                        "headers": ["일자", "매출금액" if is_seller else "매입금액", "손익마진(택배비 제외)"],
                        "rows": [
                            [
                                str(row["activity_date"] or ""),
                                int(row["amount_delta"]) if row["amount_delta"] is not None else 0,
                                int(row["margin_delta"]) if row["margin_delta"] is not None else 0,
                            ]
                            for row in amount_detail_rows
                        ],
                        "empty": "거래처별 일자 금액 데이터가 없습니다.",
                    },
                ],
            }
        raise ValueError("지원하지 않는 상세 조회 유형입니다.")
    finally:
        connection.close()


def sales_report_dashboard_payload(period: str = "", report_date: str = "") -> dict[str, object]:
    init_db()
    connection = connect_db()
    try:
        period_options = sales_report_period_options(connection)
        selected_date = report_date or ""
        selected_period = period or selected_date[:7]
        if not selected_period:
            selected_period = period_options[0] if period_options else ""
        if not selected_date and selected_period:
            row = connection.execute(
                """
                SELECT MAX(report_date) AS report_date
                  FROM (
                        SELECT report_date FROM sales_report_daily_rows WHERE period = ? AND report_date != ''
                        UNION ALL
                        SELECT report_date FROM sales_report_seller_rows WHERE period = ? AND report_date != ''
                        UNION ALL
                        SELECT report_date FROM sales_report_supplier_rows WHERE period = ? AND report_date != ''
                        UNION ALL
                        SELECT report_date FROM sales_report_product_rows WHERE period = ? AND report_date != ''
                       )
                """,
                (selected_period, selected_period, selected_period, selected_period),
            ).fetchone()
            selected_date = str(row["report_date"] or "") if row else ""
        if not selected_date:
            selected_date = date.today().isoformat()
        previous_date = previous_sales_data_date(connection, date.fromisoformat(selected_date))
        previous_period = previous_sales_period(selected_period)
        today = connection.execute(
            "SELECT * FROM sales_report_daily_rows WHERE report_date = ?",
            (selected_date,),
        ).fetchone()
        seller_today = sales_report_seller_daily_summary_row(connection, selected_date)
        if seller_today is not None:
            today = seller_today
        yesterday_public = sales_report_day_summary_from_sources(connection, previous_date)
        month = connection.execute(
            """
            SELECT COALESCE(SUM(quantity), 0) AS quantity,
                   COALESCE(SUM(sales_amount), 0) AS sales_amount,
                   COALESCE(SUM(sales_total), 0) AS sales_total,
                   COALESCE(SUM(profit_sales_amount), 0) AS profit_sales_amount,
                   COALESCE(SUM(profit_supply_amount), 0) AS profit_supply_amount,
                   COALESCE(SUM(profit_margin - profit_shipping), 0) AS profit_margin
              FROM sales_report_daily_rows
             WHERE period = ?
            """,
            (selected_period,),
        ).fetchone()
        previous_month = connection.execute(
            """
            SELECT COALESCE(SUM(quantity), 0) AS quantity,
                   COALESCE(SUM(sales_total), 0) AS sales_total,
                   COALESCE(SUM(profit_sales_amount), 0) AS profit_sales_amount,
                   COALESCE(SUM(profit_margin - profit_shipping), 0) AS profit_margin
              FROM sales_report_daily_rows
             WHERE period = ?
            """,
            (previous_period,),
        ).fetchone()
        daily_month_rows_exist = connection.execute(
            "SELECT 1 FROM sales_report_daily_rows WHERE period = ? LIMIT 1",
            (selected_period,),
        ).fetchone() is not None
        seller_date_stats = connection.execute(
            """
            SELECT COUNT(DISTINCT report_date) AS date_count,
                   MAX(report_date) AS report_date
              FROM sales_report_seller_rows
             WHERE period = ? AND report_date != ''
            """,
            (selected_period,),
        ).fetchone()
        seller_date_count = int(seller_date_stats["date_count"] or 0) if seller_date_stats else 0
        latest_seller_date = str(seller_date_stats["report_date"] or "") if seller_date_stats else ""
        seller_month_scope_active = seller_date_count > 1 or (seller_date_count > 0 and not daily_month_rows_exist)
        if seller_month_scope_active:
            seller_scope_sql = "period = ? AND report_date != '' AND report_date <= ?"
            seller_scope_params: tuple[object, ...] = (selected_period, selected_date)
        elif latest_seller_date:
            seller_scope_sql = "period = ? AND report_date = ?"
            seller_scope_params = (selected_period, latest_seller_date)
        else:
            seller_scope_sql = "period = ?"
            seller_scope_params = (selected_period,)
        if seller_month_scope_active:
            month = connection.execute(
                f"""
                SELECT COALESCE(SUM(quantity), 0) AS quantity,
                       COALESCE(SUM(sales_amount), 0) AS sales_amount,
                       COALESCE(SUM(sales_total), 0) AS sales_total,
                       COALESCE(SUM(profit_sales_amount), 0) AS profit_sales_amount,
                       COALESCE(SUM(profit_supply_amount), 0) AS profit_supply_amount,
                       COALESCE(SUM(profit_margin - profit_shipping), 0) AS profit_margin
                  FROM sales_report_seller_rows
                 WHERE {seller_scope_sql}
                """,
                seller_scope_params,
            ).fetchone()
        latest_previous_seller_date_row = connection.execute(
            "SELECT MAX(report_date) AS report_date FROM sales_report_seller_rows WHERE period = ? AND report_date != ''",
            (previous_period,),
        ).fetchone()
        latest_previous_seller_date = str(latest_previous_seller_date_row["report_date"] or "") if latest_previous_seller_date_row else ""
        latest_supplier_date_row = connection.execute(
            "SELECT MAX(report_date) AS report_date FROM sales_report_supplier_rows WHERE period = ? AND report_date != ''",
            (selected_period,),
        ).fetchone()
        latest_supplier_date = str(latest_supplier_date_row["report_date"] or "") if latest_supplier_date_row else ""
        supplier_date_stats = connection.execute(
            """
            SELECT COUNT(DISTINCT report_date) AS date_count,
                   MAX(report_date) AS report_date
              FROM sales_report_supplier_rows
             WHERE period = ? AND report_date != ''
            """,
            (selected_period,),
        ).fetchone()
        supplier_date_count = int(supplier_date_stats["date_count"] or 0) if supplier_date_stats else 0
        supplier_month_scope_active = supplier_date_count > 1 or (supplier_date_count > 0 and not daily_month_rows_exist)
        latest_previous_supplier_date_row = connection.execute(
            "SELECT MAX(report_date) AS report_date FROM sales_report_supplier_rows WHERE period = ? AND report_date != ''",
            (previous_period,),
        ).fetchone()
        latest_previous_supplier_date = str(latest_previous_supplier_date_row["report_date"] or "") if latest_previous_supplier_date_row else ""
        if supplier_month_scope_active:
            supplier_scope_sql = "period = ? AND report_date != '' AND report_date <= ?"
            supplier_scope_params: tuple[object, ...] = (selected_period, selected_date)
        elif latest_supplier_date:
            supplier_scope_sql = "period = ? AND report_date = ?"
            supplier_scope_params = (selected_period, latest_supplier_date)
        else:
            supplier_scope_sql = "period = ?"
            supplier_scope_params = (selected_period,)
        seller_total = connection.execute(
            f"""
            SELECT COALESCE(SUM(quantity), 0) AS quantity,
                   COALESCE(SUM(sales_amount), 0) AS sales_amount,
                   COALESCE(SUM(profit_sales_amount), 0) AS profit_sales_amount,
                   COALESCE(SUM(profit_margin - profit_shipping), 0) AS profit_margin
              FROM sales_report_seller_rows
             WHERE {seller_scope_sql}
            """,
            seller_scope_params,
        ).fetchone()
        previous_seller_total = connection.execute(
            """
            SELECT COALESCE(SUM(quantity), 0) AS quantity,
                   COALESCE(SUM(profit_sales_amount), 0) AS profit_sales_amount,
                   COALESCE(SUM(profit_margin - profit_shipping), 0) AS profit_margin
              FROM sales_report_seller_rows
             WHERE period = ? AND (? = '' OR report_date = ?)
            """,
            (previous_period, latest_previous_seller_date, latest_previous_seller_date),
        ).fetchone()
        supplier_purchase_total = connection.execute(
            f"""
            SELECT COALESCE(SUM(quantity), 0) AS quantity,
                   COALESCE(SUM(profit_supply_amount), 0) AS purchase_total
              FROM sales_report_supplier_rows
             WHERE {supplier_scope_sql}
            """,
            supplier_scope_params,
        ).fetchone()
        previous_supplier_purchase_total = connection.execute(
            """
            SELECT COALESCE(SUM(quantity), 0) AS quantity,
                   COALESCE(SUM(profit_supply_amount), 0) AS purchase_total
              FROM sales_report_supplier_rows
             WHERE period = ? AND (? = '' OR report_date = ?)
            """,
            (previous_period, latest_previous_supplier_date, latest_previous_supplier_date),
        ).fetchone()
        product_total = connection.execute(
            """
            SELECT COALESCE(SUM(quantity), 0) AS quantity,
                   COALESCE(SUM(profit_sales_amount), 0) AS profit_sales_amount,
                   COALESCE(SUM(profit_margin), 0) AS profit_margin
              FROM sales_report_product_rows
             WHERE period = ? AND product_name NOT LIKE ?
            """,
            (selected_period, SALES_REPORT_PRODUCT_EXCLUDE_PATTERN),
        ).fetchone()
        previous_product_total = connection.execute(
            """
            SELECT COALESCE(SUM(quantity), 0) AS quantity,
                   COALESCE(SUM(profit_sales_amount), 0) AS profit_sales_amount,
                   COALESCE(SUM(profit_margin), 0) AS profit_margin
              FROM sales_report_product_rows
             WHERE period = ? AND product_name NOT LIKE ?
            """,
            (previous_period, SALES_REPORT_PRODUCT_EXCLUDE_PATTERN),
        ).fetchone()
        daily_rows = sales_report_combined_daily_summary_rows(connection, selected_period)
        recent_daily_rows = sales_report_recent_daily_summary_rows(connection, selected_date)
        seller_rows = connection.execute(
            f"""
            SELECT seller_name AS name,
                   COALESCE(SUM(quantity), 0) AS quantity,
                   COALESCE(SUM(sales_amount), 0) AS sales_amount,
                   COALESCE(SUM(profit_sales_amount), 0) AS profit_sales_amount,
                   COALESCE(SUM(profit_shipping), 0) AS profit_shipping,
                   COALESCE(SUM(profit_margin), 0) AS profit_margin,
                   0 AS margin_rate,
                   COALESCE(SUM(cs_amount), 0) AS cs_amount,
                   COALESCE(SUM(cs_margin), 0) AS cs_margin
              FROM sales_report_seller_rows
             WHERE {seller_scope_sql}
             GROUP BY seller_name
             ORDER BY profit_sales_amount DESC, quantity DESC, seller_name COLLATE NOCASE
            """,
            seller_scope_params,
        ).fetchall()
        product_rows = connection.execute(
            """
            SELECT product_name AS name,
                   COALESCE(SUM(quantity), 0) AS quantity,
                   COALESCE(SUM(sales_amount), 0) AS sales_amount,
                   COALESCE(SUM(profit_sales_amount), 0) AS profit_sales_amount,
                   COALESCE(SUM(profit_margin), 0) AS profit_margin,
                   0 AS margin_rate,
                   COALESCE(SUM(cs_amount), 0) AS cs_amount,
                   COALESCE(SUM(cs_margin), 0) AS cs_margin
              FROM sales_report_product_rows
             WHERE period = ? AND product_name NOT LIKE ?
             GROUP BY product_name
             ORDER BY profit_sales_amount DESC, quantity DESC, product_name COLLATE NOCASE
            """,
            (selected_period, SALES_REPORT_PRODUCT_EXCLUDE_PATTERN),
        ).fetchall()
        supplier_purchase_rows = connection.execute(
            f"""
            SELECT supplier_name AS name,
                   COALESCE(SUM(quantity), 0) AS quantity,
                   COALESCE(SUM(profit_supply_amount), 0) AS purchase_total
              FROM sales_report_supplier_rows
             WHERE {supplier_scope_sql}
             GROUP BY supplier_name
             ORDER BY purchase_total DESC, quantity DESC, supplier_name COLLATE NOCASE
            """,
            supplier_scope_params,
        ).fetchall()
        daily_compare_rows = connection.execute(
            """
            WITH current_rows AS (
                SELECT CAST(substr(report_date, 9, 2) AS INTEGER) AS day_no,
                       COALESCE(SUM(quantity), 0) AS current_quantity,
                       COALESCE(SUM(profit_sales_amount), 0) AS current
                  FROM sales_report_daily_rows
                 WHERE period = ?
                 GROUP BY day_no
            ),
            previous_rows AS (
                SELECT CAST(substr(report_date, 9, 2) AS INTEGER) AS day_no,
                       COALESCE(SUM(quantity), 0) AS previous_quantity,
                       COALESCE(SUM(profit_sales_amount), 0) AS previous
                  FROM sales_report_daily_rows
                 WHERE period = ?
                 GROUP BY day_no
            ),
            keys AS (
                SELECT day_no FROM current_rows
                UNION
                SELECT day_no FROM previous_rows
            )
            SELECT printf('%d일', keys.day_no) AS label,
                   COALESCE(current_rows.current_quantity, 0) AS current_quantity,
                   COALESCE(current_rows.current, 0) AS current,
                   COALESCE(previous_rows.previous_quantity, 0) AS previous_quantity,
                   COALESCE(previous_rows.previous, 0) AS previous
              FROM keys
              LEFT JOIN current_rows ON current_rows.day_no = keys.day_no
              LEFT JOIN previous_rows ON previous_rows.day_no = keys.day_no
             ORDER BY keys.day_no
            """,
            (selected_period, previous_period),
        ).fetchall()
        product_compare_rows = connection.execute(
            """
            WITH current_rows AS (
                SELECT product_name AS label,
                       COALESCE(SUM(quantity), 0) AS current_quantity,
                       COALESCE(SUM(profit_sales_amount), 0) AS current
                  FROM sales_report_product_rows
                 WHERE period = ? AND product_name NOT LIKE ?
                 GROUP BY product_name
            ),
            previous_rows AS (
                SELECT product_name AS label,
                       COALESCE(SUM(quantity), 0) AS previous_quantity,
                       COALESCE(SUM(profit_sales_amount), 0) AS previous
                  FROM sales_report_product_rows
                 WHERE period = ? AND product_name NOT LIKE ?
                 GROUP BY product_name
            ),
            keys AS (
                SELECT label FROM current_rows
                UNION
                SELECT label FROM previous_rows
            )
            SELECT keys.label AS label,
                   COALESCE(current_rows.current_quantity, 0) AS current_quantity,
                   COALESCE(current_rows.current, 0) AS current,
                   COALESCE(previous_rows.previous_quantity, 0) AS previous_quantity,
                   COALESCE(previous_rows.previous, 0) AS previous
              FROM keys
              LEFT JOIN current_rows ON current_rows.label = keys.label
             LEFT JOIN previous_rows ON previous_rows.label = keys.label
             ORDER BY current DESC, previous DESC, keys.label COLLATE NOCASE
            """,
            (
                selected_period,
                SALES_REPORT_PRODUCT_EXCLUDE_PATTERN,
                previous_period,
                SALES_REPORT_PRODUCT_EXCLUDE_PATTERN,
            ),
        ).fetchall()
        seller_compare_rows = connection.execute(
            """
            WITH current_rows AS (
                SELECT seller_name AS label,
                       COALESCE(SUM(quantity), 0) AS current_quantity,
                       COALESCE(SUM(profit_sales_amount), 0) AS current
                  FROM sales_report_seller_rows
                 WHERE period = ? AND (? = '' OR report_date = ?)
                 GROUP BY seller_name
            ),
            previous_rows AS (
                SELECT seller_name AS label,
                       COALESCE(SUM(quantity), 0) AS previous_quantity,
                       COALESCE(SUM(profit_sales_amount), 0) AS previous
                  FROM sales_report_seller_rows
                 WHERE period = ? AND (? = '' OR report_date = ?)
                 GROUP BY seller_name
            ),
            keys AS (
                SELECT label FROM current_rows
                UNION
                SELECT label FROM previous_rows
            )
            SELECT keys.label AS label,
                   COALESCE(current_rows.current_quantity, 0) AS current_quantity,
                   COALESCE(current_rows.current, 0) AS current,
                   COALESCE(previous_rows.previous_quantity, 0) AS previous_quantity,
                   COALESCE(previous_rows.previous, 0) AS previous
              FROM keys
              LEFT JOIN current_rows ON current_rows.label = keys.label
              LEFT JOIN previous_rows ON previous_rows.label = keys.label
             ORDER BY current DESC, previous DESC, keys.label COLLATE NOCASE
            """,
            (
                selected_period,
                latest_seller_date,
                latest_seller_date,
                previous_period,
                latest_previous_seller_date,
                latest_previous_seller_date,
            ),
        ).fetchall()
        supplier_compare_rows = connection.execute(
            f"""
            WITH current_rows AS (
                SELECT supplier_name AS label,
                       COALESCE(SUM(quantity), 0) AS current_quantity,
                       COALESCE(SUM(profit_supply_amount), 0) AS current
                  FROM sales_report_supplier_rows
                 WHERE {supplier_scope_sql}
                 GROUP BY supplier_name
            ),
            previous_rows AS (
                SELECT supplier_name AS label,
                       COALESCE(SUM(quantity), 0) AS previous_quantity,
                       COALESCE(SUM(profit_supply_amount), 0) AS previous
                  FROM sales_report_supplier_rows
                 WHERE period = ? AND (? = '' OR report_date = ?)
                 GROUP BY supplier_name
            ),
            keys AS (
                SELECT label FROM current_rows
                UNION
                SELECT label FROM previous_rows
            )
            SELECT keys.label AS label,
                   COALESCE(current_rows.current_quantity, 0) AS current_quantity,
                   COALESCE(current_rows.current, 0) AS current,
                   COALESCE(previous_rows.previous_quantity, 0) AS previous_quantity,
                   COALESCE(previous_rows.previous, 0) AS previous
              FROM keys
              LEFT JOIN current_rows ON current_rows.label = keys.label
              LEFT JOIN previous_rows ON previous_rows.label = keys.label
             ORDER BY current DESC, previous DESC, keys.label COLLATE NOCASE
            """,
            (
                *supplier_scope_params,
                previous_period,
                latest_previous_supplier_date,
                latest_previous_supplier_date,
            ),
        ).fetchall()
        review_rows = connection.execute(
            """
            SELECT 'supplier' AS kind, supplier_name AS name, cs_amount, cs_margin,
                   profit_sales_amount, profit_margin
              FROM sales_report_supplier_rows
             WHERE period = ? AND (cs_amount != 0 OR cs_margin != 0 OR profit_margin < 0)
            UNION ALL
            SELECT 'seller' AS kind, seller_name AS name, cs_amount, cs_margin,
                   profit_sales_amount, profit_margin
              FROM sales_report_seller_rows
             WHERE period = ? AND (cs_amount != 0 OR cs_margin != 0 OR profit_margin < 0)
            UNION ALL
            SELECT 'product' AS kind, product_name AS name, cs_amount, cs_margin,
                   profit_sales_amount, profit_margin
              FROM sales_report_product_rows
             WHERE (? = '' OR report_date = ? OR period = ?)
               AND (cs_amount != 0 OR cs_margin != 0 OR profit_margin < 0)
             LIMIT 10
            """,
            (selected_period, selected_period, selected_date, selected_date, selected_period),
        ).fetchall()
        margin_check = sales_report_margin_check(connection, selected_period)
        report_counts = {
            "daily": sales_report_row_count_for_date(connection, "sales_report_daily_rows", selected_period, selected_date),
            "seller": sales_report_row_count_for_date(connection, "sales_report_seller_rows", selected_period, selected_date),
            "supplier": sales_report_row_count_for_date(connection, "sales_report_supplier_rows", selected_period, selected_date),
            "product": sales_report_row_count_for_date(connection, "sales_report_product_rows", selected_period, selected_date),
        }
    finally:
        connection.close()

    today_public = _sales_report_daily_public(today)
    today_amount = int(today_public.get("profit_sales_amount", 0) or 0)
    yesterday_amount = int(yesterday_public.get("profit_sales_amount", 0) or 0)
    delta = today_amount - yesterday_amount
    delta_rate = round((delta / yesterday_amount) * 100, 1) if yesterday_amount else 0
    today_quantity = int(today_public.get("quantity", 0) or 0)
    yesterday_quantity = int(yesterday_public.get("quantity", 0) or 0)
    quantity_delta = today_quantity - yesterday_quantity
    quantity_delta_rate = round((quantity_delta / yesterday_quantity) * 100, 1) if yesterday_quantity else 0
    daily_rows_public = [_sales_report_daily_public(row) for row in daily_rows]
    recent_daily_rows_public = [_sales_report_daily_public(row) for row in recent_daily_rows]
    month_total = {
        "quantity": int(month["quantity"] or 0),
        "sales_amount": int(month["sales_amount"] or 0),
        "sales_total": int(month["sales_total"] or 0),
        "profit_sales_amount": int(month["profit_sales_amount"] or 0),
        "profit_supply_amount": int(month["profit_supply_amount"] or 0),
        "profit_margin": int(month["profit_margin"] or 0),
    }
    if daily_rows_public:
        month_total = {
            "quantity": sum(int(row.get("quantity", 0) or 0) for row in daily_rows_public),
            "sales_amount": sum(int(row.get("sales_amount", 0) or 0) for row in daily_rows_public),
            "sales_total": sum(int(row.get("sales_total", 0) or 0) for row in daily_rows_public),
            "profit_sales_amount": sum(int(row.get("profit_sales_amount", 0) or 0) for row in daily_rows_public),
            "profit_supply_amount": sum(int(row.get("profit_supply_amount", 0) or 0) for row in daily_rows_public),
            "profit_margin": sum(int(row.get("profit_margin", 0) or 0) for row in daily_rows_public),
        }
    previous_month_total = {
        "quantity": int(previous_month["quantity"] or 0),
        "sales_total": int(previous_month["sales_total"] or 0),
        "profit_sales_amount": int(previous_month["profit_sales_amount"] or 0),
        "profit_margin": int(previous_month["profit_margin"] or 0),
    }
    seller_total_public = {
        "quantity": int(seller_total["quantity"] or 0),
        "sales_amount": int(seller_total["sales_amount"] or 0),
        "profit_sales_amount": int(seller_total["profit_sales_amount"] or 0),
        "profit_margin": int(seller_total["profit_margin"] or 0),
    }
    previous_seller_total_public = {
        "quantity": int(previous_seller_total["quantity"] or 0),
        "profit_sales_amount": int(previous_seller_total["profit_sales_amount"] or 0),
        "profit_margin": int(previous_seller_total["profit_margin"] or 0),
    }
    supplier_purchase_total_public = {
        "quantity": int(supplier_purchase_total["quantity"] or 0),
        "purchase_total": int(supplier_purchase_total["purchase_total"] or 0),
    }
    previous_supplier_purchase_total_public = {
        "quantity": int(previous_supplier_purchase_total["quantity"] or 0),
        "purchase_total": int(previous_supplier_purchase_total["purchase_total"] or 0),
    }
    product_total_public = {
        "quantity": int(product_total["quantity"] or 0),
        "profit_sales_amount": int(product_total["profit_sales_amount"] or 0),
        "profit_margin": int(product_total["profit_margin"] or 0),
    }
    previous_product_total_public = {
        "quantity": int(previous_product_total["quantity"] or 0),
        "profit_sales_amount": int(previous_product_total["profit_sales_amount"] or 0),
        "profit_margin": int(previous_product_total["profit_margin"] or 0),
    }
    if selected_date and any(str(row.get("report_date") or "") == selected_date for row in daily_rows_public):
        report_counts["daily"] = max(int(report_counts.get("daily", 0) or 0), 1)
    difference = month_total["profit_sales_amount"] - seller_total_public["profit_sales_amount"]
    closing_check = sales_report_closing_check(
        report_counts,
        selected_period,
        selected_date,
        month_total,
        seller_total_public,
        supplier_purchase_total_public,
        product_total_public,
        margin_check,
        len(review_rows),
    )
    return {
        "period": selected_period,
        "period_options": period_options,
        "previous_period": previous_period,
        "selected_date": selected_date,
        "previous_business_date": previous_date,
        "today_data_uploaded": bool(today_public),
        "today": today_public,
        "yesterday": yesterday_public,
        "comparison": {
            "profit_sales_amount_delta": delta,
            "profit_sales_amount_delta_rate": delta_rate,
            "quantity_delta": quantity_delta,
            "quantity_delta_rate": quantity_delta_rate,
        },
        "month": month_total,
        "previous_month": previous_month_total,
        "seller_total": seller_total_public,
        "previous_seller_total": previous_seller_total_public,
        "product_total": product_total_public,
        "previous_product_total": previous_product_total_public,
        "supplier_purchase_total": supplier_purchase_total_public,
        "previous_supplier_purchase_total": previous_supplier_purchase_total_public,
        "monthly_comparison_rows": [
            {
                "label": "월 누적 매출",
                "metric": "손익매출",
                **sales_report_delta(month_total["profit_sales_amount"], previous_month_total["profit_sales_amount"]),
            },
            {
                "label": "상품별 매출",
                "metric": "손익매출",
                **sales_report_delta(product_total_public["profit_sales_amount"], previous_product_total_public["profit_sales_amount"]),
            },
            {
                "label": "매출처 합계",
                "metric": "손익매출",
                **sales_report_delta(seller_total_public["profit_sales_amount"], previous_seller_total_public["profit_sales_amount"]),
            },
            {
                "label": "매입처 합계",
                "metric": "총 매입금액",
                **sales_report_delta(supplier_purchase_total_public["purchase_total"], previous_supplier_purchase_total_public["purchase_total"]),
            },
        ],
        "monthly_comparison_details": {
            "daily": [sales_report_compare_detail_public(row) for row in daily_compare_rows],
            "product": [sales_report_compare_detail_public(row) for row in product_compare_rows],
            "seller": [sales_report_compare_detail_public(row) for row in seller_compare_rows],
            "supplier": [sales_report_compare_detail_public(row) for row in supplier_compare_rows],
        },
        "consistency": {
            "difference": difference,
            "ok": difference == 0,
        },
        "margin_check": margin_check,
        "closing_check": closing_check,
        "daily_rows": daily_rows_public,
        "recent_daily_rows": recent_daily_rows_public,
        "seller_top": [_sales_report_named_public(row) for row in seller_rows],
        "product_top": [_sales_report_named_public(row) for row in product_rows],
        "supplier_purchase_totals": [_sales_report_purchase_public(row) for row in supplier_purchase_rows],
        "reviews": [
            {
                "kind": str(row["kind"] or ""),
                "name": str(row["name"] or ""),
                "cs_amount": int(row["cs_amount"] or 0),
                "cs_margin": int(row["cs_margin"] or 0),
                "profit_sales_amount": int(row["profit_sales_amount"] or 0),
                "profit_margin": int(row["profit_margin"] or 0),
            }
            for row in review_rows
        ],
    }


def sales_report_daily_exists(connection: sqlite3.Connection, target_date: str) -> bool:
    row = connection.execute(
        "SELECT 1 FROM sales_report_daily_rows WHERE report_date = ? LIMIT 1",
        (target_date,),
    ).fetchone()
    return bool(row)


def sales_report_alert_recipients(connection: sqlite3.Connection) -> list[str]:
    rows = connection.execute(
        """
        SELECT username, display_name, role
          FROM users
         WHERE active = 1
           AND (
                role = 'admin'
                OR username = '신성환 실장'
                OR display_name = '신성환 실장'
                OR display_name LIKE '신성환%'
           )
         ORDER BY CASE role WHEN 'admin' THEN 0 ELSE 1 END,
                  display_name COLLATE NOCASE,
                  username COLLATE NOCASE
        """
    ).fetchall()
    names: list[str] = []
    seen: set[str] = set()
    for row in rows:
        name = str(row["display_name"] or row["username"] or "").strip()
        if not name or name in seen:
            continue
        seen.add(name)
        names.append(name)
    return names


def sales_report_alert_sender_id(connection: sqlite3.Connection) -> int | None:
    row = connection.execute(
        """
        SELECT id
          FROM users
         WHERE active = 1
           AND role = 'admin'
         ORDER BY CASE
                    WHEN display_name = '신성환 실장' THEN 0
                    WHEN username = 'admin' THEN 1
                    ELSE 2
                  END,
                  id
         LIMIT 1
        """
    ).fetchone()
    if not row:
        return None
    return int(row["id"])


def can_view_automation_center(user: dict[str, object] | None) -> bool:
    if not user:
        return False
    if str(user.get("role") or "") == "admin":
        return True
    username = str(user.get("username") or "").strip()
    display_name = str(user.get("display_name") or "").strip()
    return username == "신성환 실장" or display_name == "신성환 실장" or display_name.startswith("신성환")


def can_view_import_cost_program(user: dict[str, object] | None) -> bool:
    return can_view_automation_center(user)


def import_cost_decimal(value: object, default: str = "0") -> Decimal:
    if value is None:
        return Decimal(default)
    text = str(value).strip().replace(",", "")
    if not text:
        return Decimal(default)
    try:
        return Decimal(text)
    except InvalidOperation as exc:
        raise ValueError(f"숫자 형식이 올바르지 않습니다: {value}") from exc


def import_cost_money(value: Decimal) -> int:
    return int(value.quantize(Decimal("1"), rounding=ROUND_HALF_UP))


def import_cost_unit(value: Decimal) -> float:
    return float(value.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP))


def calculate_import_cost(payload: dict) -> dict[str, object]:
    products = payload.get("products")
    if not isinstance(products, list) or not products:
        raise ValueError("제품 라인을 1개 이상 입력해주세요.")
    remittance_rate = import_cost_decimal(payload.get("remittance_rate"))
    if remittance_rate <= 0:
        raise ValueError("송금환율을 입력해주세요.")
    allocation_basis = str(payload.get("allocation_basis") or "amount").strip() or "amount"
    if allocation_basis not in {"amount", "quantity", "weight", "cbm"}:
        allocation_basis = "amount"
    include_import_vat = bool(payload.get("include_import_vat"))
    include_service_vat = bool(payload.get("include_service_vat"))
    charge_values = {
        "doc_fee": import_cost_decimal(payload.get("doc_fee")),
        "duty": import_cost_decimal(payload.get("duty")),
        "broker_fee": import_cost_decimal(payload.get("broker_fee")),
        "other_cost": import_cost_decimal(payload.get("other_cost")),
        "import_vat": import_cost_decimal(payload.get("import_vat")) if include_import_vat else Decimal("0"),
        "service_vat": import_cost_decimal(payload.get("service_vat")) if include_service_vat else Decimal("0"),
    }
    parsed_rows: list[dict[str, object]] = []
    basis_total = Decimal("0")
    invoice_total_usd = Decimal("0")
    purchase_total_krw = Decimal("0")
    for index, item in enumerate(products, start=1):
        if not isinstance(item, dict):
            raise ValueError(f"{index}번째 제품 라인이 올바르지 않습니다.")
        name = str(item.get("name") or "").strip() or f"제품 {index}"
        quantity = import_cost_decimal(item.get("quantity"))
        unit_usd = import_cost_decimal(item.get("unit_usd"))
        amount_usd = import_cost_decimal(item.get("amount_usd"))
        if amount_usd <= 0 and quantity > 0 and unit_usd > 0:
            amount_usd = quantity * unit_usd
        if quantity <= 0:
            raise ValueError(f"{name} 수량을 입력해주세요.")
        if amount_usd <= 0:
            raise ValueError(f"{name} 인보이스 금액을 입력해주세요.")
        gross_weight = import_cost_decimal(item.get("gross_weight"))
        cbm = import_cost_decimal(item.get("cbm"))
        purchase_krw = amount_usd * remittance_rate
        if allocation_basis == "quantity":
            basis_value = quantity
        elif allocation_basis == "weight":
            basis_value = gross_weight
        elif allocation_basis == "cbm":
            basis_value = cbm
        else:
            basis_value = amount_usd
        if basis_value <= 0:
            basis_value = amount_usd
        basis_total += basis_value
        invoice_total_usd += amount_usd
        purchase_total_krw += purchase_krw
        parsed_rows.append({
            "name": name,
            "quantity": quantity,
            "unit_usd": unit_usd if unit_usd > 0 else amount_usd / quantity,
            "amount_usd": amount_usd,
            "gross_weight": gross_weight,
            "cbm": cbm,
            "purchase_krw": purchase_krw,
            "basis_value": basis_value,
        })
    if basis_total <= 0:
        raise ValueError("배부 기준 합계가 0입니다.")
    allocatable_total = sum(charge_values.values(), Decimal("0"))
    result_rows: list[dict[str, object]] = []
    allocated_running = Decimal("0")
    for index, row in enumerate(parsed_rows, start=1):
        ratio = Decimal(row["basis_value"]) / basis_total
        if index == len(parsed_rows):
            allocated = allocatable_total - allocated_running
        else:
            allocated = (allocatable_total * ratio).quantize(Decimal("1"), rounding=ROUND_HALF_UP)
            allocated_running += allocated
        landed_total = Decimal(row["purchase_krw"]) + allocated
        quantity = Decimal(row["quantity"])
        result_rows.append({
            "name": row["name"],
            "quantity": import_cost_unit(quantity),
            "unit_usd": import_cost_unit(Decimal(row["unit_usd"])),
            "amount_usd": import_cost_unit(Decimal(row["amount_usd"])),
            "purchase_krw": import_cost_money(Decimal(row["purchase_krw"])),
            "allocated_cost": import_cost_money(allocated),
            "landed_total": import_cost_money(landed_total),
            "landed_unit": import_cost_unit(landed_total / quantity),
            "allocation_ratio": import_cost_unit(ratio * Decimal("100")),
        })
    return {
        "basis": allocation_basis,
        "include_import_vat": include_import_vat,
        "include_service_vat": include_service_vat,
        "summary": {
            "invoice_total_usd": import_cost_unit(invoice_total_usd),
            "purchase_total_krw": import_cost_money(purchase_total_krw),
            "allocated_cost_total": import_cost_money(allocatable_total),
            "landed_total": import_cost_money(purchase_total_krw + allocatable_total),
        },
        "charges": {key: import_cost_money(value) for key, value in charge_values.items()},
        "products": result_rows,
    }


def import_cost_cell_text(value: object) -> str:
    if value is None:
        return ""
    if isinstance(value, datetime):
        return value.date().isoformat()
    if isinstance(value, date):
        return value.isoformat()
    if isinstance(value, float) and value.is_integer():
        return str(int(value))
    return str(value).strip()


def import_cost_sheet_rows(path: Path) -> list[list[object]]:
    suffix = path.suffix.lower()
    if suffix in {".xlsx", ".xlsm"}:
        workbook = load_workbook(path, data_only=True, read_only=True)
        try:
            rows: list[list[object]] = []
            for worksheet in workbook.worksheets:
                for row in worksheet.iter_rows(values_only=True):
                    values = list(row)
                    if any(import_cost_cell_text(value) for value in values):
                        rows.append(values)
            return rows
        finally:
            workbook.close()
    if suffix == ".xls":
        try:
            import xlrd  # type: ignore
        except ImportError as exc:
            raise ValueError("xls 파일 자동 추출을 위해 서버에 xlrd 패키지가 필요합니다.") from exc
        workbook = xlrd.open_workbook(str(path))
        rows = []
        for sheet in workbook.sheets():
            for row_index in range(sheet.nrows):
                values = [sheet.cell_value(row_index, col_index) for col_index in range(sheet.ncols)]
                if any(import_cost_cell_text(value) for value in values):
                    rows.append(values)
        return rows
    if suffix == ".csv":
        text = path.read_text(encoding="utf-8-sig", errors="ignore")
        return [line.split(",") for line in text.splitlines() if line.strip()]
    return []


def import_cost_find_next_value(rows: list[list[object]], label: str) -> str:
    label_upper = label.upper()
    blocked_labels = {"DATE", "DATE:", "일자", "작성일자"}
    for row_index, row in enumerate(rows):
        texts = [import_cost_cell_text(value) for value in row]
        for col_index, text in enumerate(texts):
            if label_upper in text.upper():
                for next_value in texts[col_index + 1:]:
                    if next_value and next_value.upper() not in blocked_labels and not next_value.endswith(":"):
                        return next_value
                if row_index + 1 < len(rows):
                    next_row = [import_cost_cell_text(value) for value in rows[row_index + 1]]
                    for next_value in next_row[col_index:]:
                        if next_value:
                            return next_value
    return ""


def import_cost_number_from_text(value: object) -> Decimal:
    text = import_cost_cell_text(value)
    match = re.search(r"-?\d+(?:,\d{3})*(?:\.\d+)?|-?\d+(?:\.\d+)?", text)
    return import_cost_decimal(match.group(0) if match else "")


def import_cost_product_name_from_row(values: list[object], start: int, end: int) -> str:
    candidates = []
    blocked = {"", "N/M", "NM", "TOTAL", "TOTEL"}
    for value in values[start:end]:
        text = import_cost_cell_text(value).replace("\n", " ").strip()
        if not text or text.upper() in blocked:
            continue
        if re.fullmatch(r"\d+(?:\.\d+)?", text):
            continue
        candidates.append(text)
    return candidates[-1] if candidates else ""


def parse_import_cost_invoice_rows(rows: list[list[object]]) -> dict[str, object]:
    header_index = -1
    unit_index = amount_index = quantity_index = description_index = -1
    for row_index, row in enumerate(rows):
        headers = [import_cost_cell_text(value).upper().replace("\n", " ") for value in row]
        if not any("AMOUNT" in header for header in headers):
            continue
        unit_candidates = [idx for idx, header in enumerate(headers) if "UNIT" in header and "PRICE" in header]
        amount_candidates = [idx for idx, header in enumerate(headers) if "AMOUNT" in header]
        quantity_candidates = [
            idx for idx, header in enumerate(headers)
            if "QTY" in header or "QUANTI" in header or "수량" in header
        ]
        if unit_candidates and amount_candidates and quantity_candidates:
            header_index = row_index
            unit_index = unit_candidates[-1]
            amount_index = amount_candidates[-1]
            quantity_index = quantity_candidates[-1]
            desc_candidates = [idx for idx, header in enumerate(headers) if "DESC" in header or "품명" in header]
            description_index = desc_candidates[-1] if desc_candidates else -1
            break
    if header_index < 0:
        return {"products": [], "details": ["인보이스 상품 헤더를 찾지 못했습니다."]}

    products: list[dict[str, object]] = []
    for row in rows[header_index + 1:]:
        values = list(row)
        row_text = " ".join(import_cost_cell_text(value).upper() for value in values)
        if "TOTAL" in row_text or "TOTEL" in row_text:
            break
        quantity = import_cost_number_from_text(values[quantity_index] if quantity_index < len(values) else "")
        amount = import_cost_number_from_text(values[amount_index] if amount_index < len(values) else "")
        unit = import_cost_number_from_text(values[unit_index] if unit_index < len(values) else "")
        if quantity <= 0 and amount <= 0:
            continue
        name = ""
        if 0 <= description_index < len(values):
            name = import_cost_cell_text(values[description_index])
        if not name:
            name = import_cost_product_name_from_row(values, 0, max(quantity_index, description_index, 1))
        if not name:
            name = f"제품 {len(products) + 1}"
        products.append({
            "name": name,
            "quantity": str(quantity.normalize()),
            "unit_usd": str(unit.normalize()) if unit > 0 else "",
            "amount_usd": str(amount.normalize()) if amount > 0 else "",
        })
    details = []
    if products:
        details.append(f"인보이스 상품 {len(products)}개 라인을 추출했습니다.")
    else:
        details.append("인보이스 상품 라인이 비어 있습니다.")
    return {
        "invoice_no": import_cost_find_next_value(rows, "INVOICE NO"),
        "products": products,
        "details": details,
    }


def parse_import_cost_packing_rows(rows: list[list[object]]) -> dict[str, object]:
    header_index = -1
    quantity_index = measurement_index = weight_index = description_index = -1
    for row_index, row in enumerate(rows):
        headers = [import_cost_cell_text(value).upper().replace("\n", " ") for value in row]
        if not any("PACK" in header or "QUANTI" in header for header in headers):
            continue
        quantity_candidates = [idx for idx, header in enumerate(headers) if "QUANTI" in header or "QTY" in header]
        measure_candidates = [idx for idx, header in enumerate(headers) if "MEAS" in header or "CBM" in header]
        weight_candidates = [idx for idx, header in enumerate(headers) if "G.W" in header or "N.W" in header or "KGS" in header]
        if quantity_candidates and (measure_candidates or weight_candidates):
            header_index = row_index
            quantity_index = quantity_candidates[-1]
            measurement_index = measure_candidates[-1] if measure_candidates else -1
            weight_index = weight_candidates[-1] if weight_candidates else -1
            desc_candidates = [idx for idx, header in enumerate(headers) if "DESC" in header or "품명" in header]
            description_index = desc_candidates[-1] if desc_candidates else -1
            break
    if header_index < 0:
        return {"products": [], "details": ["패킹리스트 헤더를 찾지 못했습니다."]}
    products: list[dict[str, object]] = []
    for row in rows[header_index + 1:]:
        values = list(row)
        row_text = " ".join(import_cost_cell_text(value).upper() for value in values)
        if "TOTAL" in row_text:
            break
        quantity_text = import_cost_cell_text(values[quantity_index] if quantity_index < len(values) else "")
        quantity_matches = re.findall(r"\d+(?:,\d{3})*(?:\.\d+)?", quantity_text)
        quantity = import_cost_decimal(quantity_matches[-1] if quantity_matches else "")
        cbm = import_cost_number_from_text(values[measurement_index] if measurement_index < len(values) else "")
        weight_text = import_cost_cell_text(values[weight_index] if weight_index < len(values) else "")
        weight_matches = re.findall(r"\d+(?:,\d{3})*(?:\.\d+)?", weight_text)
        gross_weight = import_cost_decimal(weight_matches[0] if weight_matches else "")
        net_weight = import_cost_decimal(weight_matches[1] if len(weight_matches) > 1 else "")
        if quantity <= 0 and cbm <= 0 and gross_weight <= 0:
            continue
        name = ""
        if 0 <= description_index < len(values):
            name = import_cost_cell_text(values[description_index])
        if not name:
            name = import_cost_product_name_from_row(values, 0, max(quantity_index, 1))
        products.append({
            "name": name or f"제품 {len(products) + 1}",
            "quantity": str(quantity.normalize()) if quantity > 0 else "",
            "gross_weight": str(gross_weight.normalize()) if gross_weight > 0 else "",
            "net_weight": str(net_weight.normalize()) if net_weight > 0 else "",
            "cbm": str(cbm.normalize()) if cbm > 0 else "",
        })
    return {
        "products": products,
        "details": [f"패킹리스트 {len(products)}개 라인을 추출했습니다." if products else "패킹리스트 상품 라인이 비어 있습니다."],
    }


IMPORT_COST_AMOUNT_PATTERN = re.compile(r"-?\d{1,3}(?:,\d{3})+(?:\.\d+)?|-?\d+(?:\.\d+)?")

IMPORT_COST_CHARGE_TERM_EXPLANATIONS = [
    (r"OCEAN\s+FREIGHT", "OCEAN FREIGHT: 해상운임, 선박으로 운송한 기본 운임입니다."),
    (r"TERMINAL\s+HANDLING\s+CHARGE", "TERMINAL HANDLING CHARGE: 터미널 작업료, 항만 터미널에서 컨테이너를 처리하는 비용입니다."),
    (r"CONTAINER\s+CLEANING\s+FEE", "CONTAINER CLEANING FEE: 컨테이너 청소비, 반납/사용 컨테이너 청소 비용입니다."),
    (r"DOCUMENT\s+FEE", "DOCUMENT FEE: 서류 발급/처리비, 운송 관련 서류 처리 비용입니다."),
    (r"WHARFAGE", "WHARFAGE: 부두 사용료, 항만 시설 이용에 붙는 비용입니다."),
    (r"PORT\s+FACILITY\s+SECURITY", "PORT FACILITY SECURITY: 항만 보안료, 항만 보안 시설 이용 비용입니다."),
    (r"PORT\s+SAFETY\s+MANAGEMENT\s+CHARGE", "PORT SAFETY MANAGEMENT CHARGE: 항만 안전관리비, 항만 안전 관리 명목 비용입니다."),
    (r"HANDLING\s+CHARGE", "HANDLING CHARGE: 취급/처리 수수료, 포워더 또는 운송사가 처리 업무에 부과하는 비용입니다."),
    (r"TRUCKING\s+CHARGE", "TRUCKING CHARGE: 내륙 운송료, 항만에서 창고/목적지까지 차량 운송 비용입니다."),
    (r"X-?RAY", "X-RAY 검사료: 화물 보안 검사 비용입니다."),
    (r"검역수수료", "검역수수료: 수입 물품 검역 처리 비용입니다."),
]


def import_cost_amounts_from_text(value: str) -> list[str]:
    amounts = []
    for match in IMPORT_COST_AMOUNT_PATTERN.finditer(value):
        amount = match.group(0).replace(",", "")
        if amount in {"", "-"}:
            continue
        amounts.append(amount)
    return amounts


def import_cost_charge_term_details(text: str) -> list[str]:
    details = []
    seen: set[str] = set()
    for pattern, explanation in IMPORT_COST_CHARGE_TERM_EXPLANATIONS:
        if re.search(pattern, text, re.I) and explanation not in seen:
            details.append(explanation)
            seen.add(explanation)
    return details


def import_cost_amount_near_line(lines: list[str], line_index: int, window: int = 2) -> str:
    end_index = min(len(lines), line_index + window + 1)
    for index in range(line_index, end_index):
        amounts = import_cost_amounts_from_text(lines[index])
        if amounts:
            return amounts[-1]
    return ""


def import_cost_last_amount_near_label(lines: list[str], label_patterns: list[str], window: int = 2) -> str:
    for index, line in enumerate(lines):
        compact = re.sub(r"\s+", "", line)
        if not any(re.search(pattern, compact, re.I) or re.search(pattern, line, re.I) for pattern in label_patterns):
            continue
        amount = import_cost_amount_near_line(lines, index, window)
        if amount:
            return amount
    return ""


def import_cost_amount_from_total_line(lines: list[str]) -> tuple[str, str]:
    for line in lines:
        compact = re.sub(r"\s+", "", line).upper()
        if "합계" not in compact and "TOTAL" not in compact:
            continue
        amounts = import_cost_amounts_from_text(line)
        if len(amounts) >= 2:
            return amounts[-2], amounts[-1]
    return "", ""


def import_cost_jts_line_totals(lines: list[str]) -> tuple[str, str]:
    amount_total = Decimal("0")
    vat_total = Decimal("0")
    matched = 0
    for line in lines:
        if not any(re.search(pattern, line, re.I) for pattern, _ in IMPORT_COST_CHARGE_TERM_EXPLANATIONS):
            continue
        amounts = [import_cost_decimal(value) for value in import_cost_amounts_from_text(line)]
        if not amounts:
            continue
        amount = amounts[-1]
        vat = Decimal("0")
        if len(amounts) >= 2 and amounts[-2] > 0 and Decimal("0") < amounts[-1] <= amounts[-2] * Decimal("0.15"):
            amount = amounts[-2]
            vat = amounts[-1]
        amount_total += amount
        vat_total += vat
        matched += 1
    if matched < 3:
        return "", ""
    return str(amount_total.quantize(Decimal("1"), rounding=ROUND_HALF_UP)), str(vat_total.quantize(Decimal("1"), rounding=ROUND_HALF_UP))


def parse_import_cost_domestic_settlement_text(text: str) -> dict[str, object]:
    lines = [line.strip() for line in text.splitlines() if line.strip()]
    joined = "\n".join(lines)
    compact_all = re.sub(r"\s+", "", joined).upper()
    if not any(token in compact_all for token in ("통관자금", "청구정산서", "JTSSHIPPING", "TOTALAMOUNT")):
        return {"charges": {}, "details": [], "trusted": False}

    charges: dict[str, str] = {}
    details: list[str] = []
    hbl_no = ""
    hbl_match = re.search(r"\b(?:XLTSWA|XLTNGB)[A-Z0-9-]{6,}\b", joined, re.I)
    if hbl_match:
        hbl_no = hbl_match.group(0).upper()

    duty = import_cost_last_amount_near_label(lines, [r"관세"], 1)
    import_vat = import_cost_last_amount_near_label(lines, [r"부가가치세", r"부가세"], 1)
    broker_fee = import_cost_last_amount_near_label(lines, [r"통관수수료"], 1)
    do_total = import_cost_last_amount_near_label(lines, [r"D/?O비용", r"D/O\s*비용", r"DO비용"], 1)
    jts_amount, jts_vat = import_cost_amount_from_total_line(lines)
    if not jts_amount:
        jts_amount, jts_vat = import_cost_jts_line_totals(lines)
    if duty:
        charges["duty"] = duty
    if import_vat:
        charges["import_vat"] = import_vat
    if broker_fee:
        charges["broker_fee"] = broker_fee
    if jts_amount:
        charges["doc_fee"] = jts_amount
    elif do_total:
        charges["doc_fee"] = do_total
    if jts_vat:
        charges["service_vat"] = jts_vat

    claim_amount = import_cost_last_amount_near_label(lines, [r"청구금액", r"TOTALAMOUNT"], 2)
    trusted = False
    if charges:
        try:
            calculated = sum(import_cost_decimal(value) for value in charges.values())
            if claim_amount:
                trusted = abs(calculated - import_cost_decimal(claim_amount)) <= Decimal("10")
            else:
                trusted = all(charges.get(key) for key in ("import_vat", "broker_fee", "doc_fee"))
        except ValueError:
            trusted = False

    if trusted:
        details.append("국내 정산비 PDF에서 비용 합계 검증 후 자동 추출했습니다.")
    elif charges:
        details.append("국내 정산비 PDF에서 일부 금액을 읽었지만 합계 검증이 되지 않아 자동 반영하지 않았습니다.")
        charges = {}
    details.extend(import_cost_charge_term_details(joined))
    return {"charges": charges, "details": details, "trusted": trusted, "hbl_no": hbl_no}


def parse_import_cost_settlement_text(text: str) -> dict[str, str]:
    lines = [line.strip() for line in text.splitlines() if line.strip()]
    charges: dict[str, str] = {}
    broker_index = -1
    vat_indices: list[int] = []

    for index, line in enumerate(lines):
        compact = re.sub(r"\s+", "", line)
        upper_line = line.upper()
        if "통관수수료" in compact and broker_index < 0:
            broker_index = index
        if "부가세" in compact:
            vat_indices.append(index)
        if "DOC" in upper_line and "FEE" in upper_line and not charges.get("doc_fee"):
            amount = import_cost_amount_near_line(lines, index)
            if amount:
                charges["doc_fee"] = amount
        if "관세" in compact and "부가세" not in compact and "통관" not in compact and not charges.get("duty"):
            amount = import_cost_amount_near_line(lines, index)
            if amount:
                charges["duty"] = amount
        if "통관수수료" in compact and not charges.get("broker_fee"):
            amount = import_cost_amount_near_line(lines, index)
            if amount:
                charges["broker_fee"] = amount

    import_vat_index = next((index for index in vat_indices if broker_index < 0 or index < broker_index), -1)
    service_vat_index = next((index for index in vat_indices if broker_index >= 0 and index > broker_index), -1)
    if import_vat_index >= 0:
        amount = import_cost_amount_near_line(lines, import_vat_index)
        if amount:
            charges["import_vat"] = amount
    if service_vat_index >= 0:
        amount = import_cost_amount_near_line(lines, service_vat_index)
        if amount:
            charges["service_vat"] = amount

    if not charges:
        fallback_patterns = {
            "doc_fee": r"DOC\s*/\s*FEE[^\d-]{0,40}(-?\d[\d,]*(?:\.\d+)?)",
            "duty": r"관\s*세[^\d-]{0,40}(-?\d[\d,]*(?:\.\d+)?)",
            "import_vat": r"부\s*가\s*세[^\d-]{0,40}(-?\d[\d,]*(?:\.\d+)?)",
            "broker_fee": r"통\s*관\s*수\s*수\s*료[^\d-]{0,40}(-?\d[\d,]*(?:\.\d+)?)",
        }
        for key, pattern in fallback_patterns.items():
            match = re.search(pattern, text, re.I)
            if match:
                charges[key] = match.group(1).replace(",", "")
    return charges


def ocr_import_cost_pdf_text(path: Path, max_pages: int = 2) -> tuple[str, list[str]]:
    details: list[str] = []
    try:
        import fitz  # type: ignore
        import pytesseract  # type: ignore
        from PIL import Image  # type: ignore
    except Exception as exc:
        return "", [f"OCR 패키지가 준비되지 않아 스캔 PDF를 읽지 못했습니다: {exc}"]

    try:
        languages = set(pytesseract.get_languages(config=""))
        lang = "kor+eng" if {"kor", "eng"}.issubset(languages) else ("eng" if "eng" in languages else "")
        document = fitz.open(str(path))
        try:
            if document.page_count < 1:
                return "", ["PDF 페이지가 비어 있어 OCR을 실행하지 못했습니다."]
            images = []
            for page_index in range(min(document.page_count, max_pages)):
                page = document.load_page(page_index)
                pixmap = page.get_pixmap(matrix=fitz.Matrix(2, 2), alpha=False)
                images.append((page_index + 1, Image.open(BytesIO(pixmap.tobytes("png")))))
        finally:
            document.close()
    except Exception as exc:
        return "", [f"PDF 이미지 변환에 실패했습니다: {exc}"]

    texts: list[str] = []
    for page_number, image in images:
        width, height = image.size
        crop_regions = [
            (f"{page_number}페이지 전체", (0, 0, width, height)),
            (f"{page_number}페이지 비용 영역", (int(width * 0.03), int(height * 0.24), int(width * 0.98), int(height * 0.78))),
        ]
        for label, box in crop_regions:
            try:
                region = image.crop(box).convert("L")
                config = "--psm 6"
                text = pytesseract.image_to_string(region, lang=lang or None, config=config)
                if text.strip():
                    texts.append(f"[{label}]\n{text}")
            except Exception as exc:
                details.append(f"{label} OCR 실패: {exc}")
    if texts:
        details.append(f"스캔 PDF {min(len(images), max_pages)}페이지를 OCR로 읽었습니다.")
    else:
        details.append("OCR을 실행했지만 읽을 수 있는 텍스트를 찾지 못했습니다.")
    return "\n".join(texts), details


def parse_import_cost_pdf_text(path: Path) -> dict[str, object]:
    details = [f"{original_uploaded_filename(path.name)}: PDF 정산서 확인"]
    text = ""
    used_ocr = False
    try:
        from pypdf import PdfReader  # type: ignore
        reader = PdfReader(str(path))
        text = "\n".join(page.extract_text() or "" for page in reader.pages)
    except Exception:
        text = ""
    if not text.strip():
        ocr_text, ocr_details = ocr_import_cost_pdf_text(path)
        details.extend(ocr_details)
        text = ocr_text
        used_ocr = bool(text.strip())
    domestic = parse_import_cost_domestic_settlement_text(text)
    if domestic.get("details"):
        details.extend(domestic.get("details") or [])
    charges = dict(domestic.get("charges") or {})
    hbl_no = str(domestic.get("hbl_no") or "")
    if not charges:
        charges = parse_import_cost_settlement_text(text)
    if charges and used_ocr and not domestic.get("trusted"):
        details.append("스캔 PDF OCR 금액은 오인식 가능성이 있어 비용칸에 자동 반영하지 않았습니다. 정산서 원본 금액을 확인해 직접 입력해주세요.")
        charges = {}
    elif charges:
        details.append("정산 비용을 자동 추출했습니다.")
    elif text.strip():
        details.append("PDF/OCR 텍스트에서 정산 비용 항목을 찾지 못했습니다.")
    else:
        details.append("스캔 PDF라 텍스트 금액 자동 추출이 되지 않았습니다.")
    return {"charges": charges, "details": details, "hbl_no": hbl_no}


def import_cost_normalize_name(value: object) -> str:
    return re.sub(r"[^0-9a-z가-힣]+", "", str(value or "").lower())


def dedupe_import_cost_products(products: list[dict[str, object]]) -> list[dict[str, object]]:
    unique: list[dict[str, object]] = []
    seen: set[tuple[str, str, str]] = set()
    for product in products:
        key = (
            str(product.get("quantity") or "").strip(),
            str(product.get("unit_usd") or "").strip(),
            str(product.get("amount_usd") or "").strip(),
        )
        if all(key) and key in seen:
            continue
        if all(key):
            seen.add(key)
        unique.append(product)
    return unique


def merge_import_cost_products(invoice_products: list[dict[str, object]], packing_products: list[dict[str, object]]) -> list[dict[str, object]]:
    products = [dict(product) for product in dedupe_import_cost_products(invoice_products)]
    used_packing: set[int] = set()
    for product in products:
        product_key = import_cost_normalize_name(product.get("name"))
        match_index = -1
        for index, packing in enumerate(packing_products):
            if index in used_packing:
                continue
            packing_key = import_cost_normalize_name(packing.get("name"))
            if product_key and packing_key and (product_key in packing_key or packing_key in product_key):
                match_index = index
                break
        if match_index < 0 and len(products) == len(packing_products):
            candidate = len(used_packing)
            if candidate < len(packing_products):
                match_index = candidate
        if match_index >= 0:
            used_packing.add(match_index)
            packing = packing_products[match_index]
            for key in ("gross_weight", "net_weight", "cbm"):
                if packing.get(key) and not product.get(key):
                    product[key] = packing[key]
            if packing.get("quantity") and not product.get("quantity"):
                product["quantity"] = packing["quantity"]
    if not products:
        products = [dict(product) for product in packing_products]
    return products


def analyze_import_cost_files(paths: list[Path], options: dict[str, object] | None = None) -> dict[str, object]:
    options = options or {}
    invoice_products: list[dict[str, object]] = []
    packing_products: list[dict[str, object]] = []
    charges: dict[str, object] = {}
    details: list[str] = []
    invoice_no = ""
    hbl_no = ""
    parsed_files: list[dict[str, object]] = []
    for path in paths:
        original_name = original_uploaded_filename(path.name)
        suffix = path.suffix.lower()
        file_details = []
        role = "기타"
        if suffix == ".pdf":
            parsed = parse_import_cost_pdf_text(path)
            charges.update(parsed.get("charges") or {})
            if not hbl_no:
                hbl_no = str(parsed.get("hbl_no") or "")
            file_details.extend(parsed.get("details") or [])
            role = "국내 정산비 PDF" if parsed.get("charges") else "정산서 PDF"
        else:
            rows = import_cost_sheet_rows(path)
            flat_text = " ".join(import_cost_cell_text(value).upper() for row in rows for value in row[:12])
            if "PACKING" in flat_text or "装箱" in flat_text or "裝箱" in flat_text:
                parsed = parse_import_cost_packing_rows(rows)
                packing_products.extend(parsed.get("products") or [])
                file_details.extend(parsed.get("details") or [])
                role = "패킹리스트"
            elif "INVOICE" in flat_text or "发票" in flat_text or "PROFORMA" in flat_text:
                parsed = parse_import_cost_invoice_rows(rows)
                invoice_products.extend(parsed.get("products") or [])
                if not invoice_no:
                    invoice_no = str(parsed.get("invoice_no") or "")
                file_details.extend(parsed.get("details") or [])
                role = "인보이스"
            else:
                file_details.append("파일 역할을 자동 판별하지 못했습니다.")
        parsed_files.append({"name": original_name, "role": role, "details": file_details})
        details.extend(file_details)
    products = merge_import_cost_products(invoice_products, packing_products)
    payload: dict[str, object] = {
        "hbl_no": options.get("hbl_no") or hbl_no,
        "invoice_no": options.get("invoice_no") or invoice_no,
        "remittance_rate": options.get("remittance_rate") or "",
        "allocation_basis": options.get("allocation_basis") or "amount",
        "doc_fee": options.get("doc_fee") or charges.get("doc_fee") or "",
        "duty": options.get("duty") or charges.get("duty") or "",
        "broker_fee": options.get("broker_fee") or charges.get("broker_fee") or "",
        "other_cost": options.get("other_cost") or "",
        "import_vat": options.get("import_vat") or charges.get("import_vat") or "",
        "service_vat": options.get("service_vat") or charges.get("service_vat") or "",
        "include_import_vat": bool(options.get("include_import_vat", True)),
        "include_service_vat": bool(options.get("include_service_vat", True)),
        "products": products,
    }
    result = None
    calculation_error = ""
    if products and payload.get("remittance_rate"):
        try:
            result = calculate_import_cost(payload)
        except ValueError as exc:
            calculation_error = str(exc)
    elif not payload.get("remittance_rate"):
        calculation_error = "송금환율 입력 후 자동 계산됩니다."
    missing = []
    if not invoice_products:
        missing.append("인보이스 상품")
    if not packing_products:
        missing.append("패킹리스트 중량/CBM")
    if not any(payload.get(key) for key in ("doc_fee", "duty", "broker_fee", "other_cost", "import_vat", "service_vat")):
        missing.append("정산서 비용")
    return {
        "message": "수입원가 파일 분석을 완료했습니다.",
        "payload": payload,
        "result": result,
        "calculation_error": calculation_error,
        "files": parsed_files,
        "details": details,
        "missing": missing,
    }


def maybe_send_sales_report_upload_alert(now: datetime | None = None) -> bool:
    current = now or datetime.now()
    if current.hour < SALES_REPORT_UPLOAD_ALERT_HOUR:
        return False
    target_date = current.date().isoformat()
    connection = connect_db()
    try:
        if sales_report_daily_exists(connection, target_date):
            return False
        cutoff = (current - timedelta(minutes=SALES_REPORT_UPLOAD_ALERT_INTERVAL_MINUTES)).strftime("%Y-%m-%d %H:%M:%S")
        marker = f"[매출현황 업로드 요청] {target_date}"
        exists = connection.execute(
            """
            SELECT 1
              FROM internal_messages
             WHERE COALESCE(room_type, 'global') = 'global'
               AND body LIKE ?
               AND created_at >= ?
             LIMIT 1
            """,
            (f"{marker}%", cutoff),
        ).fetchone()
        if exists:
            return False
        sender_id = sales_report_alert_sender_id(connection)
        if sender_id is None:
            return False
        recipients = sales_report_alert_recipients(connection)
        recipient_text = ", ".join(recipients) if recipients else "관리자"
        message = (
            f"{marker}\n"
            f"대상: {recipient_text}\n"
            f"{current.strftime('%H:%M')} 기준 금일 매출금액이 아직 업로드되지 않았습니다.\n"
            "매출현황에 금일 매출 통계 파일을 업로드해주세요."
        )
        connection.execute(
            """
            INSERT INTO internal_messages
                (user_id, recipient_user_id, room_type, body, created_at, task_id, command_result, command_error)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (sender_id, None, "global", message, current.strftime("%Y-%m-%d %H:%M:%S"), None, "", ""),
        )
        connection.commit()
        return True
    finally:
        connection.close()


def sales_report_alert_scheduler_loop() -> None:
    while True:
        try:
            if maybe_send_sales_report_upload_alert():
                print("매출현황 업로드 요청 알림 생성")
        except Exception as exc:  # noqa: BLE001
            print(f"매출현황 업로드 알림 실패: {exc}")
        time.sleep(60)


def start_sales_report_alert_scheduler() -> None:
    global _SALES_REPORT_ALERT_SCHEDULER_STARTED
    if _SALES_REPORT_ALERT_SCHEDULER_STARTED:
        return
    _SALES_REPORT_ALERT_SCHEDULER_STARTED = True
    thread = threading.Thread(target=sales_report_alert_scheduler_loop, name="workhub-sales-report-alert", daemon=True)
    thread.start()


def latest_sales_report_context(connection: sqlite3.Connection, fallback_today: bool = True) -> tuple[str, str]:
    row = connection.execute(
        """
        SELECT report_date, period
          FROM sales_report_daily_rows
         WHERE report_date != ''
         ORDER BY report_date DESC
         LIMIT 1
        """
    ).fetchone()
    if row:
        report_date = str(row["report_date"] or "")
        period = str(row["period"] or report_date[:7] or "")
        if report_date or period:
            return report_date, period
    if not fallback_today:
        return "", ""
    today = date.today().isoformat()
    return today, today[:7]


def sales_report_date_from_upload_name(name: str, period: str = "") -> str:
    text = str(name or "")
    match = re.search(r"(20\d{2})(\d{2})(\d{2})", text)
    if match:
        year, month, day = match.groups()
        try:
            return date(int(year), int(month), int(day)).isoformat()
        except ValueError:
            return ""
    match = re.search(r"(?<!\d)(20\d{2})(\d{1,2})(\d{2})(?!\d)", text)
    if match:
        year, month, day = match.groups()
        try:
            candidate = date(int(year), int(month), int(day)).isoformat()
            return candidate if not period or candidate.startswith(period) else ""
        except ValueError:
            return ""
    if period:
        compact_period = period.replace("-", "")
        match = re.search(r"(?<!\d)(\d{1,2})(\d{2})(?!\d)", text)
        if match:
            month, day = match.groups()
            year = int(period[:4])
            try:
                candidate = date(year, int(month), int(day)).isoformat()
                return candidate if candidate.startswith(period) else ""
            except ValueError:
                return ""
        match = re.search(rf"{re.escape(compact_period)}(\d{{2}})", text)
        if match:
            try:
                return date(int(period[:4]), int(period[5:7]), int(match.group(1))).isoformat()
            except ValueError:
                return ""
    return ""


def save_manual_sales_report_entry(payload: dict[str, object], uploaded_by: str = "") -> dict[str, object]:
    init_db()
    report_date = _sales_report_date(payload.get("report_date"))
    if not report_date:
        raise ValueError("매출일자를 선택해주세요.")
    period = report_date[:7]
    seller_name = _sales_report_text(payload.get("seller_name"))
    supplier_name = _sales_report_text(payload.get("supplier_name"))
    product_name = _sales_report_text(payload.get("product_name"))
    product_code = _sales_report_text(payload.get("product_code"))
    quantity = _sales_report_int(payload.get("quantity"))
    if not seller_name:
        raise ValueError("판매처를 입력해주세요.")
    if not supplier_name:
        raise ValueError("매입처를 입력해주세요.")
    if not product_name:
        raise ValueError("품명을 입력하거나 기존 업로드 품명 목록에서 선택해주세요.")
    if quantity <= 0:
        raise ValueError("수량은 1 이상이어야 합니다.")

    sales_amount = _sales_report_int(payload.get("sales_amount"))
    supply_amount = _sales_report_int(payload.get("supply_amount"))
    sales_total = _sales_report_int(payload.get("sales_total")) or sales_amount
    supply_total = supply_amount
    sales_margin = sales_amount - supply_amount
    profit_sales_amount = sales_amount
    profit_supply_amount = supply_amount
    profit_sales_margin = sales_margin
    profit_margin = _sales_report_int(payload.get("profit_margin"))
    if profit_margin == 0 and (sales_amount or supply_amount):
        profit_margin = sales_amount - supply_amount
    margin_rate = round((profit_margin / profit_sales_amount) * 100, 1) if profit_sales_amount else 0
    uploaded_at = now_text()
    safe_product = _safe_shared_filename(product_name)[:80] or "manual-sales"
    stored_name = f"manual_sales_{datetime.now().strftime('%Y%m%d%H%M%S')}_{secrets.token_hex(6)}.json"
    original_name = f"수기 매출 등록 {report_date} {safe_product}"
    connection = connect_db()
    try:
        cursor = connection.execute(
            """
            INSERT INTO sales_report_uploads (
                stored_name, original_name, size, uploaded_by, uploaded_at,
                report_type, report_date, period, source_kind, source_fingerprint
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                stored_name,
                original_name,
                0,
                str(uploaded_by or ""),
                uploaded_at,
                "manual_sale",
                report_date,
                period,
                "manual",
                "",
            ),
        )
        file_id = int(cursor.lastrowid)
        connection.execute(
            """
            INSERT INTO sales_report_seller_rows (
                period, report_date, file_id, seller_name, quantity, sales_amount, supply_amount,
                sales_total, supply_total, sales_margin, cs_amount, cs_supply_amount, cs_margin,
                profit_quantity_sales, profit_quantity_supply, profit_sales_amount, profit_supply_amount,
                profit_sales_margin, profit_shipping, profit_margin, margin_rate
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 0, 0, 0, ?, ?, ?, ?, ?, 0, ?, ?)
            """,
            (
                period,
                report_date,
                file_id,
                seller_name,
                quantity,
                sales_amount,
                supply_amount,
                sales_total,
                supply_total,
                sales_margin,
                quantity,
                quantity,
                profit_sales_amount,
                profit_supply_amount,
                profit_sales_margin,
                profit_margin,
                margin_rate,
            ),
        )
        connection.execute(
            """
            INSERT INTO sales_report_product_rows (
                period, report_date, file_id, product_code, product_name, quantity, sales_amount,
                supply_amount, sales_total, sales_margin, cs_amount, cs_supply_amount, cs_margin,
                profit_quantity_sales, profit_quantity_supply, profit_sales_amount, profit_supply_amount,
                profit_margin, margin_rate
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 0, 0, 0, ?, ?, ?, ?, ?, ?)
            """,
            (
                period,
                report_date,
                file_id,
                product_code,
                product_name,
                quantity,
                sales_amount,
                supply_amount,
                sales_total,
                sales_margin,
                quantity,
                quantity,
                profit_sales_amount,
                profit_supply_amount,
                profit_margin,
                margin_rate,
            ),
        )
        connection.execute(
            """
            INSERT INTO sales_report_supplier_rows (
                period, report_date, file_id, supplier_name, quantity, sales_amount, supply_amount,
                sales_total, supply_total, sales_margin, cs_amount, cs_supply_amount, cs_margin,
                profit_quantity_sales, profit_quantity_supply, profit_sales_amount, profit_supply_amount,
                profit_sales_margin, profit_shipping, profit_margin, margin_rate
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 0, 0, 0, ?, ?, ?, ?, ?, 0, ?, ?)
            """,
            (
                period,
                report_date,
                file_id,
                supplier_name,
                quantity,
                sales_amount,
                supply_amount,
                sales_total,
                supply_total,
                sales_margin,
                quantity,
                quantity,
                profit_sales_amount,
                profit_supply_amount,
                profit_sales_margin,
                profit_margin,
                margin_rate,
            ),
        )
        connection.commit()
        return {
            "id": file_id,
            "original_name": original_name,
            "uploaded_by": str(uploaded_by or ""),
            "uploaded_at": uploaded_at,
            "report_type": "manual_sale",
            "report_date": report_date,
            "period": period,
            "seller_name": seller_name,
            "supplier_name": supplier_name,
            "product_name": product_name,
            "quantity": quantity,
            "profit_sales_amount": profit_sales_amount,
            "profit_margin": profit_margin,
        }
    finally:
        connection.close()


def save_sales_report_file(
    source_path: str | Path,
    original_name: str,
    uploaded_by: str = "",
    source_kind: str = "",
    source_fingerprint: str = "",
) -> dict[str, str | int]:
    source = Path(source_path)
    if not source.is_file():
        raise FileNotFoundError("매출표 파일을 찾지 못했습니다.")

    init_db()
    SALES_REPORT_DIR.mkdir(parents=True, exist_ok=True)
    safe_original = _safe_shared_filename(original_name or source.name)
    file_id = secrets.token_hex(10)
    stored_name = f"{datetime.now().strftime('%Y%m%d%H%M%S')}_{file_id}_{safe_original}"
    target = SALES_REPORT_DIR / stored_name
    target.write_bytes(source.read_bytes())
    uploaded_at = now_text()
    parsed_report: dict[str, object] | None = None
    if target.suffix.lower() == ".zip":
        parsed_report = parse_partner_daily_sales_zip(target, safe_original)
        report_type = str(parsed_report.get("report_type") or "")
    else:
        report_type = detect_sales_report_type(target, safe_original)
    report_date = ""
    period = ""
    if report_type:
        if parsed_report is None:
            parsed_report = parse_sales_report_file(target, safe_original)
        report_date = str(parsed_report.get("report_date") or "")
        period = str(parsed_report.get("period") or report_date[:7] or "")

    connection = connect_db()
    try:
        if parsed_report and report_type in {"seller", "supplier", "product"} and (not report_date or not period):
            original_date = sales_report_date_from_upload_name(safe_original, period)
            inferred_date, inferred_period = latest_sales_report_context(connection, fallback_today=not period)
            if not period:
                period = (original_date[:7] if original_date else "") or inferred_period or report_date[:7]
            if not report_date:
                if original_date and original_date.startswith(period):
                    report_date = original_date
                elif inferred_date and (not inferred_period or inferred_period == period):
                    report_date = inferred_date
            parsed_report["report_date"] = report_date
            parsed_report["period"] = period
        cursor = connection.execute(
            """
            INSERT INTO sales_report_uploads (
                stored_name, original_name, size, uploaded_by, uploaded_at,
                report_type, report_date, period, source_kind, source_fingerprint
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                stored_name,
                safe_original,
                target.stat().st_size,
                str(uploaded_by or ""),
                uploaded_at,
                report_type,
                report_date,
                period,
                str(source_kind or ""),
                str(source_fingerprint or ""),
            ),
        )
        connection.commit()
        row_id = int(cursor.lastrowid)
    finally:
        connection.close()
    if parsed_report:
        save_sales_report_snapshot(row_id, parsed_report)
    return {
        "id": row_id,
        "original_name": safe_original,
        "size": target.stat().st_size,
        "uploaded_by": str(uploaded_by or ""),
        "uploaded_at": uploaded_at,
        "report_type": report_type,
        "report_date": report_date,
        "period": period,
        "source_kind": str(source_kind or ""),
        "row_count": len(parsed_report.get("rows", [])) if parsed_report else 0,
        "source_file_count": int(parsed_report.get("source_file_count", 0)) if parsed_report else 0,
        "skipped_current_or_future_rows": int(parsed_report.get("skipped_current_or_future_rows", 0)) if parsed_report else 0,
    }


def crm_webhook_token() -> str:
    env_token = os.environ.get("WORKHUB_CRM_WEBHOOK_TOKEN", "").strip()
    return env_token or ensure_webhook_token(CRM_WEBHOOK_TOKEN_PATH)


def rotate_crm_webhook_token() -> str:
    if os.environ.get("WORKHUB_CRM_WEBHOOK_TOKEN", "").strip():
        raise ValueError("환경변수 WORKHUB_CRM_WEBHOOK_TOKEN 사용 중에는 화면에서 토큰을 재발급할 수 없습니다.")
    return rotate_webhook_token(CRM_WEBHOOK_TOKEN_PATH)


def crm_public_base_url(handler: BaseHTTPRequestHandler | None = None) -> str:
    configured = os.environ.get("WORKHUB_PUBLIC_BASE_URL", "").strip().rstrip("/")
    if configured:
        return configured
    if not handler:
        return ""
    host = handler.headers.get("X-Forwarded-Host") or handler.headers.get("Host", "")
    if not host:
        return ""
    proto = handler.headers.get("X-Forwarded-Proto")
    if not proto:
        proto = "https" if isinstance(handler.request, ssl.SSLSocket) else "http"
    return f"{proto}://{host}".rstrip("/")


def crm_webhook_public_url(handler: BaseHTTPRequestHandler | None = None) -> str:
    base_url = crm_public_base_url(handler)
    return f"{base_url}/api/crm-messenger-webhook" if base_url else "/api/crm-messenger-webhook"


def clean_payload_text(payload: dict, key: str) -> str:
    return str(payload.get(key, "") or "").strip()


def default_permissions_for_role(role: str) -> list[str]:
    return list(DEFAULT_ROLE_PERMISSIONS.get(role, DEFAULT_ROLE_PERMISSIONS["user"]))


def normalize_permissions(value: object, role: str = "user") -> list[str]:
    if role == "admin":
        return list(ALL_PERMISSIONS)
    if isinstance(value, str):
        try:
            value = json.loads(value) if value else []
        except json.JSONDecodeError:
            value = []
    if not isinstance(value, list):
        value = default_permissions_for_role(role)
    allowed = {str(item) for item in value if str(item) in ALL_PERMISSIONS}
    return [key for key in ALL_PERMISSIONS if key in allowed]


def permissions_html() -> str:
    return "\n".join(
        f"""<label class="permission-item"><input type="checkbox" value="{key}" data-permission-check /> <span>{label}<small>{description}</small></span></label>"""
        for key, label, description in PERMISSION_DEFINITIONS
    )


def role_label(role: str) -> str:
    if role == "admin":
        return "관리자"
    if role == "sub_admin":
        return "부관리자"
    return "사용자"


def security_time_text(timestamp: float | int | None) -> str:
    if not timestamp:
        return ""
    return datetime.fromtimestamp(float(timestamp)).strftime("%Y-%m-%d %H:%M:%S")


def normalize_username(value: object) -> str:
    return str(value or "").strip()


def validate_username(username: str) -> None:
    if not re.fullmatch(r"[A-Za-z0-9_.-]{3,32}", username):
        raise ValueError("아이디는 영문/숫자/._- 조합 3~32자로 입력해주세요.")


def validate_password_policy(password: str, username: str, display_name: str = "") -> None:
    if len(password) < PASSWORD_MIN_LENGTH:
        raise ValueError(f"비밀번호는 {PASSWORD_MIN_LENGTH}자 이상으로 입력해주세요.")
    if len(password) > PASSWORD_MAX_LENGTH:
        raise ValueError(f"비밀번호는 {PASSWORD_MAX_LENGTH}자 이내로 입력해주세요.")
    lowered = password.lower()
    blocked = {
        "admin" + "1234",
        "user" + "1234",
        "password",
        "password123",
        "qwer1234",
        "qwerasdf",
        "1234567890",
        "soillbridge",
        "workhub1234",
    }
    if lowered in blocked:
        raise ValueError("초기/추측 쉬운 비밀번호는 사용할 수 없습니다.")
    for value in (username, display_name):
        compact = str(value or "").strip().lower().replace(" ", "")
        if compact and len(compact) >= 3 and compact in lowered.replace(" ", ""):
            raise ValueError("비밀번호에 아이디나 표시 이름을 그대로 넣을 수 없습니다.")
    if len(set(password)) < 4:
        raise ValueError("반복 문자만 있는 비밀번호는 사용할 수 없습니다.")


def login_attempt_key(username: str, ip_address: str) -> str:
    return f"{normalize_username(username).lower()}|{ip_address or 'local'}"


def render_app_html(user: dict[str, str]) -> str:
    display_name = user.get("display_name") or user.get("username") or "사용자"
    role = role_label(user.get("role", "user"))
    display = display_name if display_name == role else f"{display_name} · {role}"
    permissions = normalize_permissions(user.get("permissions", []), user.get("role", "user"))
    is_admin = user.get("role") == "admin"
    leave_enabled = any(permission in permissions for permission in ("leave_view", "leave_approve", "leave_manage"))
    hermes_enabled = "hermes_use" in permissions
    leave_title = "연차 관리 및 신청" if any(permission in permissions for permission in ("leave_approve", "leave_manage")) else "연차 신청 및 확인"
    leave_nav = LEAVE_NAV_HTML.replace("__LEAVE_TITLE__", leave_title) if leave_enabled else ""
    leave_workspace = LEAVE_WORKSPACE_HTML.replace("__LEAVE_TITLE__", leave_title) if leave_enabled else ""
    hermes_nav = HERMES_NAV_HTML if hermes_enabled else ""
    hermes_workspace = HERMES_WORKSPACE_HTML if hermes_enabled else ""
    sales_report_enabled = "sales_report_manage" in permissions
    sales_report_nav = SALES_REPORT_NAV_HTML if sales_report_enabled else ""
    import_cost_enabled = can_view_import_cost_program(user)
    import_cost_nav = IMPORT_COST_NAV_HTML if import_cost_enabled else ""
    import_cost_workspace = IMPORT_COST_WORKSPACE_HTML if import_cost_enabled else ""
    admin_tools_nav = ADMIN_TOOLS_NAV_HTML if is_admin else ""
    admin_workspace = ADMIN_WORKSPACE_HTML.replace("__PERMISSION_CHECKBOXES__", permissions_html()) if is_admin or sales_report_enabled else ""
    backup_workspace = BACKUP_WORKSPACE_HTML if is_admin else ""
    system_workspace = SYSTEM_WORKSPACE_HTML if is_admin else ""
    return (
        HTML
        .replace("__USER_DISPLAY__", html_escape(display))
        .replace("__CURRENT_USER__", json.dumps({
            "id": int(user.get("id") or 0),
            "username": user.get("username", ""),
            "display_name": display_name,
            "role": user.get("role", "user"),
        }, ensure_ascii=False))
        .replace("__LEAVE_NAV__", leave_nav)
        .replace("__HERMES_NAV__", hermes_nav)
        .replace("__SALES_REPORT_NAV__", sales_report_nav)
        .replace("__IMPORT_COST_NAV__", import_cost_nav)
        .replace("__LEAVE_WORKSPACE__", leave_workspace)
        .replace("__HERMES_WORKSPACE__", hermes_workspace)
        .replace("__ADMIN_TOOLS_NAV__", admin_tools_nav)
        .replace("__ADMIN_WORKSPACE__", admin_workspace)
        .replace("__IMPORT_COST_WORKSPACE__", import_cost_workspace)
        .replace("__BACKUP_WORKSPACE__", backup_workspace)
        .replace("__SYSTEM_WORKSPACE__", system_workspace)
        .replace("__USER_PERMISSIONS__", json.dumps(permissions, ensure_ascii=False))
        .replace("__PERMISSION_LABELS__", json.dumps({key: label for key, label, _ in PERMISSION_DEFINITIONS}, ensure_ascii=False))
    )


def render_login_html(show_error: bool = False, login_error: str = "", message: str = "", register_error: str = "") -> str:
    return (
        LOGIN_HTML
        .replace("__LOGIN_ERROR_DISPLAY__", "block" if show_error or login_error else "none")
        .replace("__LOGIN_ERROR__", html_escape(login_error or "아이디 또는 비밀번호가 올바르지 않습니다."))
        .replace("__LOGIN_MESSAGE_DISPLAY__", "block" if message else "none")
        .replace("__LOGIN_MESSAGE__", html_escape(message))
        .replace("__REGISTER_ERROR_DISPLAY__", "block" if register_error else "none")
        .replace("__REGISTER_ERROR__", html_escape(register_error))
    )


def password_hash(password: str, salt: str | None = None) -> str:
    salt = salt or secrets.token_hex(16)
    iterations = 260000
    digest = hashlib.pbkdf2_hmac("sha256", password.encode("utf-8"), salt.encode("utf-8"), iterations)
    return f"pbkdf2_sha256${iterations}${salt}${digest.hex()}"


def verify_password(password: str, stored_hash: str) -> bool:
    try:
        algorithm, iterations_text, salt, expected = stored_hash.split("$", 3)
        if algorithm != "pbkdf2_sha256":
            return False
        iterations = int(iterations_text)
        digest = hashlib.pbkdf2_hmac("sha256", password.encode("utf-8"), salt.encode("utf-8"), iterations)
        return hmac.compare_digest(digest.hex(), expected)
    except ValueError:
        return False


def configured_initial_admin() -> tuple[str, str, str] | None:
    password = os.environ.get("WORKHUB_INITIAL_ADMIN_PASSWORD", "").strip()
    if not password:
        return None
    username = normalize_username(os.environ.get("WORKHUB_INITIAL_ADMIN_USERNAME", "admin"))
    display_name = str(os.environ.get("WORKHUB_INITIAL_ADMIN_NAME", "관리자")).strip() or username
    validate_username(username)
    validate_password_policy(password, username, display_name)
    return username, display_name, password


def create_bootstrap_user(
    connection: sqlite3.Connection,
    username: str,
    display_name: str,
    role: str,
    password: str,
    timestamp: str,
) -> None:
    connection.execute(
        """
        INSERT INTO users (username, display_name, role, permissions, password_hash, active, created_at, updated_at)
        VALUES (?, ?, ?, ?, ?, 1, ?, ?)
        """,
        (
            username,
            display_name,
            role,
            json.dumps(default_permissions_for_role(role), ensure_ascii=False),
            password_hash(password),
            timestamp,
            timestamp,
        ),
    )


def bootstrap_initial_users(connection: sqlite3.Connection, timestamp: str) -> None:
    user_count = int(connection.execute("SELECT COUNT(*) FROM users").fetchone()[0])
    if user_count:
        return

    initial_admin = configured_initial_admin()
    if initial_admin:
        username, display_name, password = initial_admin
        create_bootstrap_user(connection, username, display_name, "admin", password, timestamp)
        return

    if WORKHUB_PRODUCTION:
        return

    for username, display_name, role in DEFAULT_LOCAL_BOOTSTRAP_USERS:
        create_bootstrap_user(
            connection,
            username,
            display_name,
            role,
            secrets.token_urlsafe(32),
            timestamp,
        )


def token_digest(token: str) -> str:
    return hashlib.sha256(token.encode("utf-8")).hexdigest()


def parse_iso_date(value: object) -> date:
    try:
        return date.fromisoformat(str(value or "").strip())
    except ValueError as exc:
        raise ValueError("날짜 형식이 올바르지 않습니다.") from exc


def is_half_step(value: float) -> bool:
    return abs(value * 2 - round(value * 2)) < 0.000001


def clean_leave_days(value: object, label: str) -> float:
    try:
        days = float(str(value).strip())
    except ValueError as exc:
        raise ValueError(f"{label}는 숫자로 입력해주세요.") from exc
    if days < 0 or not is_half_step(days):
        raise ValueError(f"{label}는 0 이상, 0.5일 단위로 입력해주세요.")
    return round(days, 2)


def company_holiday_dates(start: date, end: date) -> set[str]:
    connection = connect_db()
    try:
        rows = connection.execute(
            "SELECT holiday_date FROM company_holidays WHERE holiday_date BETWEEN ? AND ?",
            (start.isoformat(), end.isoformat()),
        ).fetchall()
        return {str(row["holiday_date"]) for row in rows}
    except sqlite3.OperationalError:
        return set()
    finally:
        connection.close()


def save_company_holiday(holiday_date: str, name: str, is_substitute: bool = False) -> None:
    init_db()
    parsed_date = parse_iso_date(holiday_date)
    clean_name = str(name or "").strip() or "\uD734\uC77C"
    now = now_text()
    connection = connect_db()
    try:
        connection.execute(
            """
            INSERT INTO company_holidays (holiday_date, name, is_substitute, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?)
            ON CONFLICT(holiday_date) DO UPDATE SET
                name = excluded.name,
                is_substitute = excluded.is_substitute,
                updated_at = excluded.updated_at
            """,
            (parsed_date.isoformat(), clean_name, 1 if is_substitute else 0, now, now),
        )
        connection.commit()
    finally:
        connection.close()


def calculate_leave_days(start: date, end: date, unit: str, excluded_dates: set[str] | None = None) -> float:
    if start > end:
        raise ValueError("\uC2DC\uC791\uC77C\uC740 \uC885\uB8CC\uC77C\uBCF4\uB2E4 \uB2A6\uC744 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4.")
    excluded_dates = excluded_dates if excluded_dates is not None else company_holiday_dates(start, end)
    if unit == "HALF_DAY":
        if start != end:
            raise ValueError("\uBC18\uCC28\uB294 \uD558\uB8E8\uB9CC \uC2E0\uCCAD\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.")
        if start.weekday() >= 5 or start.isoformat() in excluded_dates:
            raise ValueError("\uC8FC\uB9D0 \uB610\uB294 \uACF5\uD734\uC77C\uC5D0\uB294 \uBC18\uCC28\uB97C \uC2E0\uCCAD\uD560 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4.")
        return 0.5
    days = 0
    cursor = start
    while cursor <= end:
        if cursor.weekday() < 5 and cursor.isoformat() not in excluded_dates:
            days += 1
        cursor = date.fromordinal(cursor.toordinal() + 1)
    if days <= 0:
        raise ValueError("\uC2E0\uCCAD \uAC00\uB2A5\uD55C \uADFC\uBB34\uC77C\uC774 \uC5C6\uC2B5\uB2C8\uB2E4.")
    return float(days)


def leave_status_label(status: str) -> str:
    return {
        "PENDING": "승인대기",
        "APPROVED": "승인완료",
        "REJECTED": "반려",
        "CANCELED": "취소",
        "HISTORICAL": "기존사용",
    }.get(status, status)


def connect_db() -> sqlite3.Connection:
    CONFIG_DIR.mkdir(parents=True, exist_ok=True)
    connection = sqlite3.connect(DB_PATH)
    connection.row_factory = sqlite3.Row
    return connection


def normalize_vendor_type(value: object) -> str:
    text = re.sub(r"[\s/_-]+", "", str(value or "").strip().lower())
    if text in {"매출", "매출처", "매출거래처", "판매처", "sales", "seller", "customer"}:
        return "sales"
    return "purchase"


def vendor_type_label(vendor_type: object) -> str:
    return "매출처" if normalize_vendor_type(vendor_type) == "sales" else "매입처"


def normalize_company_key(value: object) -> str:
    text = str(value or "").strip().lower()
    text = re.sub(r"\(주\)|㈜|주식회사|[\s\(\)\[\]{}./_-]+", "", text)
    return text


