def update_cs_case(case_id: int, payload: dict) -> None:
    init_db()
    connection = connect_db()
    try:
        previous = connection.execute(
            f"SELECT {', '.join(CS_CASE_UPDATE_FIELDS)}, return_invoice_updated_at, reship_invoice_updated_at FROM cs_cases WHERE id = ?",
            (case_id,),
        ).fetchone()
        if not previous:
            raise ValueError("수정할 CS건을 찾지 못했습니다.")
        values = {
            field: clean_payload_text(payload, field) if field in payload else (previous[field] or "")
            for field in CS_CASE_UPDATE_FIELDS
        }
        status = values["status"] or (previous["status"] or "")
        cs_type = values["cs_type"]
        cs_content = values["cs_content"]
        return_invoice = values["return_invoice"]
        reship_invoice = values["reship_invoice"]
        now = now_text()
        return_invoice_updated_at = None
        reship_invoice_updated_at = None
        if return_invoice and return_invoice != (previous["return_invoice"] or ""):
            return_invoice_updated_at = now
        if reship_invoice and reship_invoice != (previous["reship_invoice"] or ""):
            reship_invoice_updated_at = now
        if "status" not in payload and should_mark_cs_case_complete(cs_type, cs_content, return_invoice, reship_invoice):
            status = "전체 처리완료"
        completed_at = values["completed_at"]
        if "전체 처리완료" in status and not completed_at.strip():
            completed_at = date.today().isoformat()
        values["status"] = status
        values["completed_at"] = completed_at
        assignments = ",\n                    ".join(f"{field} = ?" for field in CS_CASE_UPDATE_FIELDS)
        cursor = connection.execute(
            f"""
            UPDATE cs_cases
               SET {assignments},
                   return_invoice_updated_at = COALESCE(?, return_invoice_updated_at),
                   reship_invoice_updated_at = COALESCE(?, reship_invoice_updated_at),
                   updated_at = ?
             WHERE id = ?
            """,
            [
                *[values[field] for field in CS_CASE_UPDATE_FIELDS],
                return_invoice_updated_at,
                reship_invoice_updated_at,
                now,
                case_id,
            ],
        )
        connection.commit()
        if cursor.rowcount == 0:
            raise ValueError("수정할 CS건을 찾지 못했습니다.")
    finally:
        connection.close()


def list_cs_followup_alerts() -> list[dict[str, str | int]]:
    init_db()
    target_date = (date.today() - timedelta(days=1)).isoformat()
    connection = connect_db()
    try:
        rows = connection.execute(
            """
            SELECT id, status, cs_type, product_name, receiver_name, return_invoice,
                   reship_invoice, sales_vendor, purchase_vendor, updated_at,
                   return_invoice_updated_at, reship_invoice_updated_at
              FROM cs_cases
             WHERE COALESCE(status, '') NOT LIKE '%전체 처리완료%'
               AND (
                    substr(COALESCE(return_invoice_updated_at, ''), 1, 10) = ?
                    OR substr(COALESCE(reship_invoice_updated_at, ''), 1, 10) = ?
               )
             ORDER BY updated_at DESC, id DESC
             LIMIT 30
            """,
            (target_date, target_date),
        ).fetchall()
    finally:
        connection.close()
    return [dict(row) for row in rows]


def delete_cs_cases(case_ids: list[int]) -> int:
    init_db()
    if not case_ids:
        return 0
    placeholders = ", ".join("?" for _ in case_ids)
    connection = connect_db()
    try:
        source_rows = connection.execute(
            f"""
            SELECT source_file, source_sheet, source_row
              FROM cs_cases
             WHERE id IN ({placeholders})
            """,
            case_ids,
        ).fetchall()
        cursor = connection.execute(f"DELETE FROM cs_cases WHERE id IN ({placeholders})", case_ids)
        management_prefix = "통합관리대장:"
        for row in source_rows:
            source_file = str(row["source_file"] or "")
            if not source_file.startswith(management_prefix):
                continue
            connection.execute(
                """
                UPDATE management_records
                   SET cs_received_at = ''
                 WHERE source_file = ?
                   AND source_sheet = ?
                   AND source_row = ?
                """,
                [
                    source_file[len(management_prefix):],
                    row["source_sheet"],
                    row["source_row"],
                ],
            )
        connection.commit()
        return int(cursor.rowcount or 0)
    finally:
        connection.close()


def management_query_conditions(
    query: str = "",
    year: str = "",
    month: str = "",
    filters: dict[str, object] | None = None,
    exclude_filter: str = "",
) -> tuple[str, list[object]]:
    query = query.strip()
    params: list[object] = []
    conditions: list[str] = []
    if query:
        pattern = f"%{query}%"
        conditions.append(
            """
            (
                purchase_vendor LIKE ?
                OR sales_vendor LIKE ?
                OR transaction_type LIKE ?
                OR ledger_checked LIKE ?
                OR order_date LIKE ?
                OR ship_date LIKE ?
                OR orderer_name LIKE ?
                OR sender_phone LIKE ?
                OR receiver_name LIKE ?
                OR receiver_phone LIKE ?
                OR product_name LIKE ?
                OR receiver_address LIKE ?
                OR courier LIKE ?
                OR invoice_number LIKE ?
                OR memo LIKE ?
                OR order_item_id LIKE ?
                OR product_code LIKE ?
                OR order_number LIKE ?
                OR customer_option LIKE ?
            )
            """
        )
        params = [pattern] * 19
    period_condition, period_params = management_period_condition(year, month)
    if period_condition:
        conditions.append(period_condition)
        params.extend(period_params)
    for field, raw_value in (filters or {}).items():
        if field == exclude_filter or field not in MANAGEMENT_FILTER_FIELDS:
            continue
        value = clean_cell(raw_value)
        if not value:
            continue
        conditions.append(f"COALESCE({field}, '') LIKE ?")
        params.append(f"%{value}%")
    where = f"WHERE {' AND '.join(conditions)}" if conditions else ""
    return where, params

def list_management_records(
    query: str = "",
    limit: int | None = 300,
    year: str = "",
    month: str = "",
    filters: dict[str, object] | None = None,
) -> list[dict[str, str | int]]:
    init_db()
    where, params = management_query_conditions(query, year, month, filters)
    connection = connect_db()
    try:
        limit_sql = ""
        if limit is not None:
            limit_sql = "LIMIT ?"
            params.append(limit)
        rows = connection.execute(
            f"""
            SELECT id, created_at, source_file, source_sheet, source_row, purchase_vendor,
                   sales_vendor, transaction_type, ledger_checked, order_date, ship_date,
                   orderer_name, sender_phone, receiver_name, receiver_phone, product_name,
                   quantity, receiver_address, courier, invoice_number, memo, order_item_id,
                   product_code, order_number, customer_option, cs_received_at
              FROM management_records
              {where}
             ORDER BY order_date DESC,
                      CASE
                        WHEN TRIM(quantity) GLOB '[0-9]*' THEN CAST(quantity AS REAL)
                        ELSE 999999999
                      END ASC,
                      product_name ASC,
                      purchase_vendor ASC,
                      sales_vendor ASC,
                      id ASC
             {limit_sql}
            """,
            params,
        ).fetchall()
    finally:
        connection.close()
    return [dict(row) for row in rows]

def list_management_filter_options(
    field: str,
    query: str = "",
    year: str = "",
    month: str = "",
    filters: dict[str, object] | None = None,
    search: str = "",
    limit: int = 500,
) -> list[dict[str, str | int]]:
    init_db()
    field = clean_cell(field)
    if field not in MANAGEMENT_FILTER_FIELDS:
        raise ValueError("지원하지 않는 통합관리대장 필터입니다.")
    if not clean_cell(year) or not clean_cell(month):
        raise ValueError("통합관리대장 필터는 월을 먼저 선택한 뒤 사용할 수 있습니다.")
    where, params = management_query_conditions(query, year, month, filters, exclude_filter=field)
    search = clean_cell(search)
    if search:
        where = f"{where} AND COALESCE({field}, '') LIKE ?" if where else f"WHERE COALESCE({field}, '') LIKE ?"
        params.append(f"%{search}%")
    limit = min(max(int(limit or 500), 1), 2000)
    params.append(limit)
    connection = connect_db()
    try:
        rows = connection.execute(
            f"""
            SELECT value, COUNT(*) AS count, MIN(id) AS record_id
              FROM (
                    SELECT TRIM(COALESCE({field}, '')) AS value, id
                      FROM management_records
                      {where}
                   )
             WHERE value != ''
             GROUP BY value
             ORDER BY value COLLATE NOCASE
             LIMIT ?
            """,
            params,
        ).fetchall()
    finally:
        connection.close()
    return [
        {"value": str(row["value"] or ""), "count": int(row["count"] or 0), "record_id": int(row["record_id"] or 0)}
        for row in rows
    ]

def management_filters_from_params(params: dict[str, list[str]]) -> dict[str, str]:
    filters: dict[str, str] = {}
    for field in MANAGEMENT_FILTER_FIELDS:
        value = params.get(f"filter_{field}", [""])[0]
        value = clean_cell(value)
        if value:
            filters[field] = value
    return filters

def list_management_records_by_ids(record_ids: list[int]) -> list[dict[str, str | int]]:
    init_db()
    if not record_ids:
        return []
    placeholders = ", ".join("?" for _ in record_ids)
    order_case = " ".join(f"WHEN {record_id} THEN {index}" for index, record_id in enumerate(record_ids))
    connection = connect_db()
    try:
        rows = connection.execute(
            f"""
            SELECT id, created_at, source_file, source_sheet, source_row, purchase_vendor,
                   sales_vendor, transaction_type, ledger_checked, order_date, ship_date,
                   orderer_name, sender_phone, receiver_name, receiver_phone, product_name,
                   quantity, receiver_address, courier, invoice_number, memo, order_item_id,
                   product_code, order_number, customer_option, cs_received_at
              FROM management_records
             WHERE id IN ({placeholders})
             ORDER BY CASE id {order_case} END
            """,
            record_ids,
        ).fetchall()
    finally:
        connection.close()
    return [dict(row) for row in rows]

def list_management_periods() -> list[dict[str, str | int]]:
    init_db()
    connection = connect_db()
    try:
        rows = connection.execute(
            """
            SELECT order_date, ship_date
              FROM management_records
             WHERE COALESCE(order_date, '') <> '' OR COALESCE(ship_date, '') <> ''
            """
        ).fetchall()
    finally:
        connection.close()

    counts: dict[tuple[str, str], int] = {}
    for row in rows:
        year_month = extract_year_month(row["order_date"], row["ship_date"])
        if not year_month:
            continue
        counts[year_month] = counts.get(year_month, 0) + 1
    return [
        {"year": year, "month": month, "count": count}
        for (year, month), count in sorted(counts.items(), key=lambda item: (item[0][0], item[0][1]), reverse=True)
    ]


