def save_portal_notice(payload: dict, user: dict[str, str]) -> dict[str, str | int]:
    init_db()
    notice_date = clean_payload_text(payload, "date") or date.today().isoformat()
    title = clean_payload_text(payload, "title")
    owner = clean_payload_text(payload, "owner")
    body = clean_payload_text(payload, "body")
    if not title and not body:
        raise ValueError("공지 제목 또는 내용을 입력해주세요.")
    now = now_text()
    created_by = str(user.get("username") or user.get("display_name") or "")
    connection = connect_db()
    try:
        cursor = connection.execute(
            """
            INSERT INTO portal_notices (created_at, updated_at, notice_date, title, owner, body, created_by)
            VALUES (?, ?, ?, ?, ?, ?, ?)
            """,
            (now, now, notice_date, title, owner, body, created_by),
        )
        notice_id = int(cursor.lastrowid)
        connection.commit()
    finally:
        connection.close()
    saved = [row for row in list_portal_notices(limit=1) if int(row["id"]) == notice_id]
    return saved[0] if saved else {
        "id": notice_id,
        "created_at": now,
        "updated_at": now,
        "date": notice_date,
        "title": title,
        "owner": owner,
        "body": body,
        "created_by": created_by,
    }


def delete_portal_notice(notice_id: int) -> int:
    init_db()
    if not notice_id:
        raise ValueError("삭제할 공지사항 ID가 없습니다.")
    connection = connect_db()
    try:
        cursor = connection.execute("DELETE FROM portal_notices WHERE id = ?", (notice_id,))
        connection.commit()
        return int(cursor.rowcount or 0)
    finally:
        connection.close()


def save_cargo_shipment(payload: dict) -> int:
    init_db()
    now = now_text()
    values = {field: clean_payload_text(payload, field) for field in CARGO_SHIPMENT_FIELDS}
    values["cargo_type"] = "inbound" if values.get("cargo_type") == "inbound" else "outbound"
    if not any(value for key, value in values.items() if key != "cargo_type"):
        raise ValueError("화물 입출고 내용을 입력해주세요.")
    if not values["status"]:
        values["status"] = "입고 예정" if values["cargo_type"] == "inbound" else "출고 예정"
    cargo_id = int(payload.get("id") or 0)
    completed_at = now if values["status"] in {"출고 완료", "입고 완료"} else ""
    connection = connect_db()
    try:
        if cargo_id:
            assignments = ", ".join(f"{field} = ?" for field in CARGO_SHIPMENT_FIELDS)
            cursor = connection.execute(
                f"UPDATE cargo_shipments SET {assignments}, completed_at = ?, updated_at = ? WHERE id = ?",
                [values[field] for field in CARGO_SHIPMENT_FIELDS] + [completed_at, now, cargo_id],
            )
            if cursor.rowcount == 0:
                raise ValueError("수정할 화물 입출고건을 찾지 못했습니다.")
        else:
            columns = ["created_at", "updated_at", *CARGO_SHIPMENT_FIELDS, "completed_at"]
            placeholders = ", ".join("?" for _ in columns)
            cursor = connection.execute(
                f"INSERT INTO cargo_shipments ({', '.join(columns)}) VALUES ({placeholders})",
                [now, now] + [values[field] for field in CARGO_SHIPMENT_FIELDS] + [completed_at],
            )
            cargo_id = int(cursor.lastrowid)
        connection.commit()
        return cargo_id
    finally:
        connection.close()


