def import_correction_id(correction: dict[str, object]) -> int:
    raw_id = clean_cell(correction.get("id"))
    return int(raw_id) if raw_id.isdigit() else 0


def fetch_management_import_rows(connection: sqlite3.Connection, record_ids: list[int]) -> list[dict[str, object]]:
    if not record_ids:
        return []
    placeholders = ", ".join("?" for _ in record_ids)
    order_case = " ".join(f"WHEN {record_id} THEN {index}" for index, record_id in enumerate(record_ids))
    rows = connection.execute(
        f"""
        SELECT id, {', '.join(MANAGEMENT_IMPORT_COLUMNS)}
          FROM management_records
         WHERE id IN ({placeholders})
         ORDER BY CASE id {order_case} END
        """,
        record_ids,
    ).fetchall()
    return [dict(row) for row in rows]


def fetch_cs_import_rows(connection: sqlite3.Connection, case_ids: list[int]) -> list[dict[str, object]]:
    if not case_ids:
        return []
    placeholders = ", ".join("?" for _ in case_ids)
    order_case = " ".join(f"WHEN {case_id} THEN {index}" for index, case_id in enumerate(case_ids))
    rows = connection.execute(
        f"""
        SELECT id, {', '.join(CS_IMPORT_COLUMNS)}
          FROM cs_cases
         WHERE id IN ({placeholders})
         ORDER BY CASE id {order_case} END
        """,
        case_ids,
    ).fetchall()
    return [dict(row) for row in rows]


def apply_management_import_corrections_to_db(corrections: list[dict[str, object]]) -> dict[str, object]:
    init_db()
    corrections_by_id = {
        record_id: correction
        for correction in corrections
        if isinstance(correction, dict) and (record_id := import_correction_id(correction))
    }
    if not corrections_by_id:
        return {"updated": 0, "invalid_rows": [], "invalid_count": 0, "has_invalid_rows": False}
    record_ids = list(corrections_by_id.keys())
    editable_columns = [column for column in MANAGEMENT_IMPORT_COLUMNS if column in MANAGEMENT_IMPORT_EDITABLE_FIELDS]
    assignments = ", ".join(f"{column} = ?" for column in editable_columns)
    connection = connect_db()
    updated = 0
    try:
        rows = fetch_management_import_rows(connection, record_ids)
        for row in rows:
            correction = corrections_by_id.get(int(row["id"]))
            if not correction:
                continue
            merged = dict(row)
            for field in MANAGEMENT_IMPORT_EDITABLE_FIELDS:
                if field in correction:
                    merged[field] = clean_cell(correction.get(field))
            normalize_management_import_records([merged])
            cursor = connection.execute(
                f"UPDATE management_records SET {assignments} WHERE id = ?",
                [merged.get(column, "") for column in editable_columns] + [row["id"]],
            )
            updated += int(cursor.rowcount or 0)
        connection.commit()
        refreshed = fetch_management_import_rows(connection, record_ids)
    finally:
        connection.close()
    invalid_rows = management_import_invalid_rows(refreshed)
    return {
        "updated": updated,
        "invalid_rows": invalid_rows,
        "invalid_count": len(invalid_rows),
        "has_invalid_rows": bool(invalid_rows),
    }


def apply_cs_import_corrections_to_db(corrections: list[dict[str, object]]) -> dict[str, object]:
    init_db()
    corrections_by_id = {
        case_id: correction
        for correction in corrections
        if isinstance(correction, dict) and (case_id := import_correction_id(correction))
    }
    if not corrections_by_id:
        return {"updated": 0, "invalid_rows": [], "invalid_count": 0, "has_invalid_rows": False}
    case_ids = list(corrections_by_id.keys())
    editable_columns = [column for column in CS_IMPORT_COLUMNS if column in CS_IMPORT_EDITABLE_FIELDS]
    assignments = ", ".join(f"{column} = ?" for column in editable_columns)
    connection = connect_db()
    updated = 0
    now = now_text()
    try:
        rows = fetch_cs_import_rows(connection, case_ids)
        for row in rows:
            correction = corrections_by_id.get(int(row["id"]))
            if not correction:
                continue
            merged = dict(row)
            previous_return_invoice = clean_cell(row.get("return_invoice"))
            previous_reship_invoice = clean_cell(row.get("reship_invoice"))
            for field in CS_IMPORT_EDITABLE_FIELDS:
                if field in correction:
                    merged[field] = clean_cell(correction.get(field))
            normalize_cs_import_records([merged])
            if should_mark_cs_case_complete(
                clean_cell(merged.get("cs_type")),
                clean_cell(merged.get("cs_content")),
                clean_cell(merged.get("return_invoice")),
                clean_cell(merged.get("reship_invoice")),
            ):
                merged["status"] = "전체 처리완료"
                if not clean_cell(merged.get("completed_at")):
                    merged["completed_at"] = date.today().isoformat()
            return_invoice_updated_at = now if clean_cell(merged.get("return_invoice")) and clean_cell(merged.get("return_invoice")) != previous_return_invoice else None
            reship_invoice_updated_at = now if clean_cell(merged.get("reship_invoice")) and clean_cell(merged.get("reship_invoice")) != previous_reship_invoice else None
            cursor = connection.execute(
                f"""
                UPDATE cs_cases
                   SET {assignments},
                       updated_at = ?,
                       return_invoice_updated_at = COALESCE(?, return_invoice_updated_at),
                       reship_invoice_updated_at = COALESCE(?, reship_invoice_updated_at)
                 WHERE id = ?
                """,
                [merged.get(column, "") for column in editable_columns]
                + [now, return_invoice_updated_at, reship_invoice_updated_at, row["id"]],
            )
            updated += int(cursor.rowcount or 0)
        connection.commit()
        refreshed = fetch_cs_import_rows(connection, case_ids)
    finally:
        connection.close()
    invalid_rows = cs_import_invalid_rows(refreshed)
    return {
        "updated": updated,
        "invalid_rows": invalid_rows,
        "invalid_count": len(invalid_rows),
        "has_invalid_rows": bool(invalid_rows),
    }


def parse_import_corrections(fields: dict[str, tuple[str, bytes] | str]) -> list[dict[str, object]] | None:
    raw = fields.get("corrections")
    if not isinstance(raw, str) or not raw.strip():
        return None
    parsed = json.loads(raw)
    if not isinstance(parsed, list):
        raise ValueError("수정 데이터 형식이 올바르지 않습니다.")
    return [item for item in parsed if isinstance(item, dict)]


class DataBlob(ctypes.Structure):
    _fields_ = [
        ("cbData", ctypes.c_ulong),
        ("pbData", ctypes.POINTER(ctypes.c_char)),
    ]


def protect_text(value: str) -> str:
    if not value:
        return ""
    if os.name != "nt":
        return TOKEN_PREFIX_KEY + protect_text_with_secret(value)
    raw = value.encode("utf-8")
    in_buffer = ctypes.create_string_buffer(raw)
    in_blob = DataBlob(len(raw), ctypes.cast(in_buffer, ctypes.POINTER(ctypes.c_char)))
    out_blob = DataBlob()
    if not ctypes.windll.crypt32.CryptProtectData(
        ctypes.byref(in_blob),
        None,
        None,
        None,
        None,
        0,
        ctypes.byref(out_blob),
    ):
        raise OSError("메일 비밀번호 저장 암호화에 실패했습니다.")
    try:
        encrypted = ctypes.string_at(out_blob.pbData, out_blob.cbData)
        return TOKEN_PREFIX_DPAPI + base64.b64encode(encrypted).decode("ascii")
    finally:
        ctypes.windll.kernel32.LocalFree(out_blob.pbData)


def unprotect_text(value: str) -> str:
    if not value:
        return ""
    if value.startswith(TOKEN_PREFIX_KEY):
        return unprotect_text_with_secret(value.removeprefix(TOKEN_PREFIX_KEY))
    if value.startswith(TOKEN_PREFIX_DPAPI):
        value = value.removeprefix(TOKEN_PREFIX_DPAPI)
    if os.name != "nt":
        return unprotect_text_with_secret(value)
    raw = base64.b64decode(value.encode("ascii"))
    in_buffer = ctypes.create_string_buffer(raw)
    in_blob = DataBlob(len(raw), ctypes.cast(in_buffer, ctypes.POINTER(ctypes.c_char)))
    out_blob = DataBlob()
    if not ctypes.windll.crypt32.CryptUnprotectData(
        ctypes.byref(in_blob),
        None,
        None,
        None,
        None,
        0,
        ctypes.byref(out_blob),
    ):
        raise OSError("저장된 메일 비밀번호를 읽지 못했습니다.")
    try:
        decrypted = ctypes.string_at(out_blob.pbData, out_blob.cbData)
        return decrypted.decode("utf-8")
    finally:
        ctypes.windll.kernel32.LocalFree(out_blob.pbData)


def get_server_secret() -> bytes:
    env_secret = os.environ.get("WORKHUB_SECRET_KEY", "").strip()
    if env_secret:
        return hashlib.sha256(env_secret.encode("utf-8")).digest()

    CONFIG_DIR.mkdir(parents=True, exist_ok=True)
    if SECRET_KEY_PATH.exists():
        return base64.b64decode(SECRET_KEY_PATH.read_text(encoding="utf-8").strip())

    secret = secrets.token_bytes(32)
    SECRET_KEY_PATH.write_text(base64.b64encode(secret).decode("ascii"), encoding="utf-8")
    try:
        os.chmod(SECRET_KEY_PATH, 0o600)
    except OSError:
        pass
    return secret


def key_stream(secret: bytes, nonce: bytes, size: int) -> bytes:
    chunks: list[bytes] = []
    counter = 0
    while sum(len(chunk) for chunk in chunks) < size:
        chunks.append(hashlib.sha256(secret + nonce + counter.to_bytes(4, "big")).digest())
        counter += 1
    return b"".join(chunks)[:size]


def protect_text_with_secret(value: str) -> str:
    secret = get_server_secret()
    nonce = secrets.token_bytes(16)
    raw = value.encode("utf-8")
    encrypted = bytes(left ^ right for left, right in zip(raw, key_stream(secret, nonce, len(raw))))
    signature = hmac.new(secret, nonce + encrypted, hashlib.sha256).digest()
    return base64.b64encode(nonce + signature + encrypted).decode("ascii")


def unprotect_text_with_secret(value: str) -> str:
    secret = get_server_secret()
    raw = base64.b64decode(value.encode("ascii"))
    nonce = raw[:16]
    signature = raw[16:48]
    encrypted = raw[48:]
    expected = hmac.new(secret, nonce + encrypted, hashlib.sha256).digest()
    if not hmac.compare_digest(signature, expected):
        raise OSError("저장된 메일 비밀번호 검증에 실패했습니다.")
    decrypted = bytes(left ^ right for left, right in zip(encrypted, key_stream(secret, nonce, len(encrypted))))
    return decrypted.decode("utf-8")


def normalize_naver_email(value: object) -> str:
    email = str(value or "").strip()
    if email and "@" not in email:
        email = f"{email}@naver.com"
    return email


def clean_int_setting(value: object, default: int, minimum: int, maximum: int) -> int:
    try:
        parsed = int(value)
    except (TypeError, ValueError):
        return default
    return min(max(parsed, minimum), maximum)


def normalize_mail_technical_settings(settings: dict | None = None) -> dict[str, str | int]:
    source = settings or {}
    smtp_port = clean_int_setting(
        source.get("smtp_port"),
        int(DEFAULT_MAIL_TECHNICAL_SETTINGS["smtp_port"]),
        1,
        65535,
    )
    smtp_security = str(source.get("smtp_security") or "").strip().lower()
    if smtp_security not in {"ssl", "tls"}:
        smtp_security = "tls" if smtp_port == 587 else "ssl"
    if smtp_security == "ssl" and smtp_port not in {465, 587}:
        smtp_port = 465
    if smtp_security == "tls" and smtp_port not in {465, 587}:
        smtp_port = 587

    return {
        "smtp_host": NAVER_SMTP_HOST,
        "smtp_port": smtp_port,
        "smtp_security": smtp_security,
        "bulk_batch_size": clean_int_setting(
            source.get("bulk_batch_size"),
            int(DEFAULT_MAIL_TECHNICAL_SETTINGS["bulk_batch_size"]),
            1,
            100,
        ),
        "bulk_send_interval_seconds": clean_int_setting(
            source.get("bulk_send_interval_seconds"),
            int(DEFAULT_MAIL_TECHNICAL_SETTINGS["bulk_send_interval_seconds"]),
            5,
            600,
        ),
        "bulk_batch_pause_minutes": clean_int_setting(
            source.get("bulk_batch_pause_minutes"),
            int(DEFAULT_MAIL_TECHNICAL_SETTINGS["bulk_batch_pause_minutes"]),
            0,
            120,
        ),
        "bulk_test_recipient": str(source.get("bulk_test_recipient") or "").strip(),
    }


def load_mail_settings(include_password: bool = False) -> dict[str, str | int | bool]:
    defaults = normalize_mail_technical_settings(DEFAULT_MAIL_TECHNICAL_SETTINGS)
    if not MAIL_SETTINGS_PATH.exists():
        return {"naver_email": "", "has_password": False, **defaults}
    try:
        settings = json.loads(MAIL_SETTINGS_PATH.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return {"naver_email": "", "has_password": False, **defaults}
    password_token = str(settings.get("password_token", ""))
    loaded: dict[str, str | int | bool] = {
        "naver_email": str(settings.get("naver_email", "")),
        "has_password": bool(password_token),
        **normalize_mail_technical_settings(settings),
    }
    if include_password and password_token:
        loaded["naver_password"] = unprotect_text(password_token)
    return loaded


def save_mail_settings(
    naver_email: str,
    naver_password: str | None = None,
    bulk_settings: dict | None = None,
) -> None:
    settings = load_mail_settings(include_password=False)
    settings["naver_email"] = naver_email
    settings.update(normalize_mail_technical_settings({**settings, **(bulk_settings or {})}))
    if naver_password:
        settings["password_token"] = protect_text(naver_password)
        settings["has_password"] = True
    else:
        existing = {}
        if MAIL_SETTINGS_PATH.exists():
            try:
                existing = json.loads(MAIL_SETTINGS_PATH.read_text(encoding="utf-8"))
            except (OSError, json.JSONDecodeError):
                existing = {}
        if existing.get("password_token"):
            settings["password_token"] = existing["password_token"]
    CONFIG_DIR.mkdir(parents=True, exist_ok=True)
    MAIL_SETTINGS_PATH.write_text(json.dumps(settings, ensure_ascii=False, indent=2), encoding="utf-8")


DEFAULT_HERMES_SETTINGS = {
    "enabled": env_bool("HERMES_ENABLED", False),
    "profile": os.environ.get("HERMES_PROFILE", "vps"),
    "base_url": os.environ.get("HERMES_BASE_URL", "http://hermes-agent:4871"),
    "health_path": os.environ.get("HERMES_HEALTH_PATH", "/health"),
    "chat_path": os.environ.get("HERMES_CHAT_PATH", "/api/chat"),
    "automation_path": os.environ.get("HERMES_AUTOMATION_PATH", "/api/automation"),
    "api_key": os.environ.get("HERMES_API_KEY", ""),
    "timeout_seconds": env_int("HERMES_TIMEOUT_SECONDS", 20, minimum=3),
}


def normalize_hermes_settings(payload: dict | None = None) -> dict[str, object]:
    source = {**DEFAULT_HERMES_SETTINGS, **(payload or {})}
    base_url = str(source.get("base_url") or "").strip().rstrip("/")
    if base_url and not base_url.startswith(("http://", "https://")):
        base_url = f"http://{base_url}"

    def clean_path(name: str, default: str) -> str:
        value = str(source.get(name) or default).strip() or default
        return value if value.startswith("/") else f"/{value}"

    return {
        "enabled": bool(source.get("enabled")),
        "profile": str(source.get("profile") or "vps").strip() or "vps",
        "base_url": base_url,
        "health_path": clean_path("health_path", "/health"),
        "chat_path": clean_path("chat_path", "/api/chat"),
        "automation_path": clean_path("automation_path", "/api/automation"),
        "api_key": str(source.get("api_key") or "").strip(),
        "timeout_seconds": min(max(int(source.get("timeout_seconds") or 20), 3), 240),
    }


def load_hermes_settings(include_secret: bool = False) -> dict[str, object]:
    raw: dict[str, object] = {}
    if HERMES_SETTINGS_PATH.exists():
        try:
            raw = json.loads(HERMES_SETTINGS_PATH.read_text(encoding="utf-8"))
        except (OSError, json.JSONDecodeError):
            raw = {}
    settings = normalize_hermes_settings(raw)
    if not include_secret:
        settings["has_api_key"] = bool(settings.get("api_key"))
        settings["api_key"] = ""
    return settings


def save_hermes_settings(payload: dict) -> dict[str, object]:
    current = load_hermes_settings(include_secret=True)
    merged = {**current, **payload}
    if not str(payload.get("api_key") or "").strip():
        merged["api_key"] = current.get("api_key", "")
    settings = normalize_hermes_settings(merged)
    CONFIG_DIR.mkdir(parents=True, exist_ok=True)
    HERMES_SETTINGS_PATH.write_text(json.dumps(settings, ensure_ascii=False, indent=2), encoding="utf-8")
    return load_hermes_settings(include_secret=False)


def normalize_hermes_chat_mode(value: object) -> str:
    mode = str(value or "auto").strip().lower()
    return mode if mode in {"auto", "automation", "general", "search", "image"} else "auto"


def hermes_chat_intent(message: str, mode: str = "auto") -> str:
    mode = normalize_hermes_chat_mode(mode)
    if mode == "search":
        return "web_search"
    if mode == "image":
        return "image_generation"
    if mode in {"automation", "general"}:
        return "chat"
    text = str(message or "").strip().lower()
    if text.startswith(("/검색", "검색:", "search:")) or any(token in text for token in ("검색해", "찾아봐", "최신", "뉴스", "인터넷")):
        return "web_search"
    if text.startswith(("/이미지", "이미지:", "image:")) or any(token in text for token in ("이미지 만들어", "그림 만들어", "로고 만들어", "배너 만들어", "포스터 만들어")):
        return "image_generation"
    return "chat"


def hermes_sales_report_scope(message: object = "") -> str:
    text = str(message or "").strip().lower()
    if any(token in text for token in ("오늘", "금일", "당일", "today")):
        return "today"
    if any(token in text for token in ("이번 달", "이번달", "월간", "월 누계", "월누계", "누계", "month", "monthly")):
        return "month"
    return "default"


def hermes_sales_report_context(payload: dict[str, object], scope: str = "default") -> dict[str, object]:
    scope = scope if scope in {"today", "month", "default"} else "default"
    base = {
        "period": payload.get("period", ""),
        "selected_date": payload.get("selected_date", ""),
        "scope": scope,
    }
    if scope == "today":
        return {
            **base,
            "today_only": True,
            "instruction": "User asked for today's/current-day sales. Use sales_report.today only for sales figures. Do not answer with monthly cumulative totals.",
            "today_data_uploaded": payload.get("today_data_uploaded", False),
            "today": payload.get("today", {}),
            "previous_business_date": payload.get("previous_business_date", ""),
            "yesterday": payload.get("yesterday", {}),
            "comparison": payload.get("comparison", {}),
            "closing_check": payload.get("closing_check", {}),
        }
    if scope == "month":
        return {
            **base,
            "today_only": False,
            "instruction": "User asked for month/cumulative sales. Use monthly cumulative fields and label them as month-to-date totals.",
            "month": payload.get("month", {}),
            "seller_total": payload.get("seller_total", {}),
            "supplier_purchase_total": payload.get("supplier_purchase_total", {}),
            "top_sellers": payload.get("seller_top", [])[:5],
            "top_products": payload.get("product_top", [])[:5],
            "closing_check": payload.get("closing_check", {}),
        }
    return {
        **base,
        "today_only": False,
        "instruction": "If the user's wording says today/current-day, use sales_report.today only. Use month fields only when the user asks for month or cumulative totals.",
        "today_data_uploaded": payload.get("today_data_uploaded", False),
        "today": payload.get("today", {}),
        "month": payload.get("month", {}),
        "seller_total": payload.get("seller_total", {}),
        "supplier_purchase_total": payload.get("supplier_purchase_total", {}),
        "top_sellers": payload.get("seller_top", [])[:5],
        "top_products": payload.get("product_top", [])[:5],
        "closing_check": payload.get("closing_check", {}),
    }


def hermes_workhub_context_snapshot(message: object = "") -> dict[str, object]:
    init_db()
    connection = connect_db()
    try:
        sales_period = latest_sales_report_period(connection)
        sales_date, _ = latest_sales_report_context(connection, fallback_today=False)
        cs_status_rows = connection.execute(
            """
            SELECT COALESCE(NULLIF(status, ''), '미지정') AS status, COUNT(*) AS count
              FROM cs_cases
             GROUP BY COALESCE(NULLIF(status, ''), '미지정')
             ORDER BY count DESC
             LIMIT 8
            """
        ).fetchall()
        management_recent_rows = connection.execute(
            """
            SELECT substr(COALESCE(NULLIF(ship_date, ''), NULLIF(order_date, '')), 1, 10) AS activity_date,
                   COUNT(*) AS count
              FROM management_records
             WHERE COALESCE(NULLIF(ship_date, ''), NULLIF(order_date, '')) != ''
             GROUP BY substr(COALESCE(NULLIF(ship_date, ''), NULLIF(order_date, '')), 1, 10)
             ORDER BY activity_date DESC
             LIMIT 7
            """
        ).fetchall()
        latest_management = connection.execute(
            "SELECT COUNT(*) AS count FROM management_records"
        ).fetchone()
        shared_files = list_shared_files()[:5]
    finally:
        connection.close()

    sales_summary: dict[str, object] = {}
    if sales_period:
        try:
            payload = sales_report_dashboard_payload(sales_period, sales_date)
            sales_summary = hermes_sales_report_context(payload, hermes_sales_report_scope(message))
        except Exception as exc:
            sales_summary = {"error": str(exc)}
    try:
        automation_overview = workhub_automation_overview()
        automation_summary = {
            "status": automation_overview.get("status", ""),
            "issue_count": automation_overview.get("issue_count", 0),
            "briefing": automation_overview.get("briefing", []),
            "sections": automation_overview.get("sections", {}),
        }
    except Exception as exc:  # noqa: BLE001
        automation_summary = {"error": str(exc)}

    return {
        "generated_at": now_text(),
        "sales_report": sales_summary,
        "automation_overview": automation_summary,
        "cs_status_counts": [{"status": str(row["status"]), "count": int(row["count"] or 0)} for row in cs_status_rows],
        "management": {
            "total_records": int(latest_management["count"] or 0) if latest_management else 0,
            "recent_dates": [{"date": str(row["activity_date"] or ""), "count": int(row["count"] or 0)} for row in management_recent_rows],
        },
        "recent_shared_files": shared_files,
    }


def hermes_capabilities_payload(intent: str = "chat", mode: str = "auto") -> dict[str, object]:
    return {
        "chat": True,
        "workhub_context": True,
        "automation_planning": True,
        "web_search": "Codex-backed Hermes agent by default; direct OpenAI web_search only when WORKHUB_AI_TOOL_PROVIDER=openai",
        "image_generation": "Codex-backed Hermes agent by default; direct OpenAI image API only when WORKHUB_AI_TOOL_PROVIDER=openai",
        "downloadable_results": True,
        "available_chat_modes": ["auto", "automation", "general", "search", "image"],
        "requested_mode": normalize_hermes_chat_mode(mode),
        "requested_intent": intent,
    }


def hermes_text_result_requested(message: object) -> bool:
    text = str(message or "").strip().lower()
    return any(token in text for token in (
        "txt",
        "텍스트 파일",
        "파일로",
        "다운로드 링크",
        "다운로드 가능",
        "다운로드할 수",
        "결과물 파일",
    ))


def _safe_hermes_result_id(value: object) -> str:
    result_id = str(value or "").strip()
    if not re.fullmatch(r"[A-Za-z0-9_-]{12,80}", result_id):
        raise ValueError("결과 파일을 찾지 못했습니다.")
    return result_id


def _hermes_result_paths(result_id: object) -> tuple[Path, Path]:
    safe_id = _safe_hermes_result_id(result_id)
    base_dir = HERMES_RESULT_DIR.resolve()
    data_path = (HERMES_RESULT_DIR / safe_id).resolve()
    meta_path = (HERMES_RESULT_DIR / f"{safe_id}.json").resolve()
    if base_dir not in data_path.parents or base_dir not in meta_path.parents:
        raise ValueError("결과 파일을 찾지 못했습니다.")
    return data_path, meta_path


def _hermes_result_public(result_id: str, metadata: dict[str, object]) -> dict[str, object]:
    return {
        "id": result_id,
        "name": str(metadata.get("original_name") or metadata.get("filename") or "Hermes 결과물"),
        "original_name": str(metadata.get("original_name") or metadata.get("filename") or "Hermes 결과물"),
        "filename": str(metadata.get("filename") or metadata.get("original_name") or "Hermes 결과물"),
        "mime": str(metadata.get("mime") or "application/octet-stream"),
        "size": int(metadata.get("size") or 0),
        "download_url": f"/api/hermes-result-download?id={quote(result_id)}",
        "saveable": True,
        "saved": False,
    }


def save_hermes_temp_result(data: bytes, original_name: str, mime: str = "application/octet-stream") -> dict[str, object]:
    HERMES_RESULT_DIR.mkdir(parents=True, exist_ok=True)
    result_id = secrets.token_urlsafe(18).replace("-", "_")
    data_path, meta_path = _hermes_result_paths(result_id)
    safe_original = _safe_shared_filename(original_name or f"hermes_result_{datetime.now().strftime('%Y%m%d_%H%M%S')}")
    data_path.write_bytes(data)
    metadata = {
        "original_name": safe_original,
        "filename": safe_original,
        "mime": mime or mimetypes.guess_type(safe_original)[0] or "application/octet-stream",
        "size": len(data),
        "created_at": now_text(),
    }
    meta_path.write_text(json.dumps(metadata, ensure_ascii=False), encoding="utf-8")
    return _hermes_result_public(result_id, metadata)


def hermes_result_download_info(result_id: object) -> tuple[Path, dict[str, object]]:
    data_path, meta_path = _hermes_result_paths(result_id)
    if not data_path.is_file() or not meta_path.is_file():
        raise ValueError("결과 파일을 찾지 못했습니다.")
    metadata = json.loads(meta_path.read_text(encoding="utf-8"))
    return data_path, metadata


def save_hermes_result_to_shared(result_id: object, uploaded_by: str = "") -> dict[str, object]:
    data_path, metadata = hermes_result_download_info(result_id)
    saved = save_shared_file(data_path, str(metadata.get("original_name") or data_path.name), uploaded_by)
    saved["download_url"] = f"/api/shared-file-download?id={saved['id']}"
    saved["saved"] = True
    return saved


def save_hermes_generated_image(data: dict[str, object], uploaded_by: str = "") -> dict[str, object] | None:
    image_base64 = str(data.get("image_base64") or "")
    if not image_base64:
        return None
    image_mime = str(data.get("image_mime") or "image/png").lower()
    extension = ".jpg" if "jpeg" in image_mime or "jpg" in image_mime else ".png"
    image_bytes = base64.b64decode(image_base64)
    return save_hermes_temp_result(
        image_bytes,
        f"hermes_generated_{datetime.now().strftime('%Y%m%d_%H%M%S')}{extension}",
        image_mime,
    )


def save_hermes_text_result(text: str, mode: str = "auto", uploaded_by: str = "") -> dict[str, object] | None:
    text = str(text or "").strip()
    if not text:
        return None
    return save_hermes_temp_result(
        text.encode("utf-8"),
        f"hermes_{normalize_hermes_chat_mode(mode)}_{datetime.now().strftime('%Y%m%d_%H%M%S')}.txt",
        "text/plain; charset=utf-8",
    )


def describe_hermes_connection_error(exc: Exception, url: str, base_url: str) -> str:
    if isinstance(exc, urllib.error.HTTPError):
        if exc.code in (401, 403):
            return f"Hermes Agent 인증 실패({exc.code})입니다. API 키 설정을 확인해주세요. 요청 주소: {url}"
        if exc.code == 404:
            return f"Hermes Agent 경로를 찾지 못했습니다. Health/채팅/자동화 경로를 확인해주세요. 요청 주소: {url}"
        return f"Hermes Agent 응답 오류({exc.code})입니다. 요청 주소: {url}"
    reason = getattr(exc, "reason", exc)
    reason_text = str(reason)
    if "timed out" in reason_text.lower() or "timeout" in reason_text.lower():
        return f"Hermes Agent 연결 시간이 초과됐습니다. Agent 실행 상태와 방화벽을 확인해주세요. 요청 주소: {url}"
    if "refused" in reason_text.lower() or "10061" in reason_text:
        return f"Hermes Agent가 응답하지 않습니다. Agent 컨테이너/포트가 실행 중인지 확인해주세요. 기본 주소: {base_url}"
    if "name or service not known" in reason_text.lower() or "nodename" in reason_text.lower() or "11001" in reason_text:
        return f"Hermes Agent 주소를 찾지 못했습니다. 로컬에서는 테스트 주소를, VPS에서는 같은 Docker 네트워크의 서비스명을 사용해주세요. 기본 주소: {base_url}"
    return f"Hermes Agent 연결 실패: {reason_text}"


def hermes_request(path_key: str, payload: dict | None = None) -> dict[str, object]:
    settings = load_hermes_settings(include_secret=True)
    if not settings.get("enabled"):
        raise ValueError("Hermes Agent 사용 설정이 꺼져 있습니다.")
    base_url = str(settings.get("base_url") or "").strip().rstrip("/")
    if not base_url:
        raise ValueError("Hermes Agent 기본 주소를 먼저 저장해주세요.")
    path = str(settings.get(path_key) or "").strip()
    url = f"{base_url}{path if path.startswith('/') else '/' + path}"
    headers = {"Accept": "application/json"}
    data = None
    if payload is not None:
        data = json.dumps(payload, ensure_ascii=False).encode("utf-8")
        headers["Content-Type"] = "application/json; charset=utf-8"
    api_key = str(settings.get("api_key") or "").strip()
    if api_key:
        if api_key.lower().startswith(("basic ", "bearer ")):
            headers["Authorization"] = api_key
        else:
            headers["Authorization"] = f"Bearer {api_key}"
        headers["X-Hermes-Api-Key"] = api_key
    request = urllib.request.Request(url, data=data, headers=headers, method="POST" if payload is not None else "GET")
    try:
        with urllib.request.urlopen(request, timeout=int(settings.get("timeout_seconds") or 20)) as response:
            body = response.read().decode("utf-8", errors="replace")
            try:
                parsed = json.loads(body) if body else {}
            except json.JSONDecodeError:
                parsed = {"text": body}
            return {"ok": True, "status": response.status, "url": url, "data": parsed}
    except urllib.error.HTTPError as exc:
        body = exc.read().decode("utf-8", errors="replace")
        message = describe_hermes_connection_error(exc, url, base_url)
        if body:
            message = f"{message} / 응답: {body[:500]}"
        raise ValueError(message) from exc
    except Exception as exc:
        raise ValueError(describe_hermes_connection_error(exc, url, base_url)) from exc


def append_hermes_history(kind: str, title: str, status: str, message: str, extra: dict | None = None) -> None:
    CONFIG_DIR.mkdir(parents=True, exist_ok=True)
    item = {
        "created_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        "kind": kind,
        "title": title[:120],
        "status": status,
        "message": message[:1000],
    }
    if not extra:
        if kind.startswith("AI "):
            extra = {"category": "chat"}
        elif "Hermes Agent" in title:
            extra = {"category": "system"}
        else:
            extra = {"category": "automation"}
    if extra:
        item.update(extra)
    with HERMES_HISTORY_PATH.open("a", encoding="utf-8") as handle:
        handle.write(json.dumps(item, ensure_ascii=False) + "\n")


def list_hermes_history(limit: int = 80) -> list[dict[str, str]]:
    if not HERMES_HISTORY_PATH.exists():
        return []
    rows: list[dict[str, str]] = []
    for line in HERMES_HISTORY_PATH.read_text(encoding="utf-8").splitlines()[-limit:]:
        try:
            item = json.loads(line)
        except json.JSONDecodeError:
            continue
        rows.append({key: str(item.get(key, "")) for key in ("created_at", "kind", "title", "status", "message", "category", "summary", "source_count", "action_id", "task_id")})
    return list(reversed(rows))


def hermes_result_text(result: dict[str, object]) -> str:
    payload = result.get("data", result)
    if isinstance(payload, str):
        return payload
    if isinstance(payload, dict):
        for key in ("summary", "answer", "message", "text", "content", "result", "reply"):
            value = payload.get(key)
            if value:
                return str(value)
        return json.dumps(payload, ensure_ascii=False)
    return str(payload or "")


def summarize_hermes_chat_history(limit: int = 20) -> dict[str, str]:
    history = list(reversed(list_hermes_history(limit=200)))
    chat_items = [
        item for item in history
        if item.get("category") == "chat" or "채팅" in item.get("kind", "") or "chat" in item.get("kind", "").lower()
    ]
    chat_items = chat_items[-limit:]
    if not chat_items:
        raise ValueError("요약할 헤르메스 채팅내역이 없습니다.")
    lines = []
    for item in chat_items:
        title = item.get("title", "").strip()
        message = item.get("message", "").strip()
        lines.append(f"- {item.get('created_at', '')} / 질문: {title} / 응답: {message[:300]}")
    prompt = (
        "다음 Workhub 헤르메스 업무채팅 내역을 업무 인계용으로 요약해주세요.\n"
        "형식: 핵심요약, 결정사항, 해야 할 일, 확인 필요 항목.\n\n"
        + "\n".join(lines)
    )
    summary_status = "기본요약"
    try:
        result = hermes_request("chat_path", {
            "message": prompt,
            "source": "workhub",
            "task": "summarize_chat_history",
            "history": chat_items,
        })
        summary_text = hermes_result_text(result)
        summary_status = "성공"
    except Exception:
        topics = [item.get("title", "").strip() for item in chat_items if item.get("title", "").strip()]
        summary_text = f"최근 헤르메스 채팅 {len(chat_items)}건 기준 요약 초안입니다.\n"
        summary_text += "주요 질문: " + " / ".join(topics[:5])
        if len(topics) > 5:
            summary_text += f" 외 {len(topics) - 5}건"
        summary_text += "\n헤르메스 Agent 연결 후 다시 요약하면 더 정교한 업무 요약을 생성할 수 있습니다."
    summary = {
        "title": f"헤르메스 채팅 요약 {datetime.now().strftime('%Y-%m-%d %H:%M')}",
        "summary": summary_text[:2000],
        "source_count": str(len(chat_items)),
        "category": "summary",
    }
    append_hermes_history(
        "채팅 요약",
        summary["title"],
        summary_status,
        summary["summary"],
        {"category": "summary", "summary": summary["summary"], "source_count": summary["source_count"]},
    )
    return summary


def hermes_status_payload() -> dict[str, object]:
    settings = load_hermes_settings(include_secret=False)
    if not settings.get("enabled"):
        return {"ok": False, "message": "Hermes Agent 사용 설정이 꺼져 있습니다.", "settings": settings}
    try:
        result = hermes_request("health_path")
        return {"ok": True, "message": "Hermes Agent에 연결됐습니다.", "status": result.get("status"), "settings": settings}
    except Exception as exc:
        return {"ok": False, "message": str(exc), "settings": settings}


